import React, { useState } from 'react'

type BulkDeleteResponse = {
  ok: boolean
  total: number
  deleted_count: number
  failed_count: number
  failed?: Array<{
    tenant_id: string
    name?: string
    detail?: string
  }>
}

type Props = {
  companyCount: number
  onClose: () => void
  onConfirm: () => Promise<BulkDeleteResponse>
}

const CONFIRM_TEXT = 'DELETE ALL'

export const DeleteAllCompaniesModal: React.FC<Props> = ({ companyCount, onClose, onConfirm }) => {
  const [confirmText, setConfirmText] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [result, setResult] = useState<BulkDeleteResponse | null>(null)

  const handleSubmit = async () => {
    if (confirmText.trim().toUpperCase() !== CONFIRM_TEXT) {
      setError('Confirmation text does not match')
      return
    }
    try {
      setLoading(true)
      setError(null)
      const res = await onConfirm()
      setResult(res)
    } catch (e: any) {
      setError(e?.response?.data?.detail || e?.message || 'Bulk delete failed')
      setLoading(false)
    }
  }

  if (result) {
    return (
      <div
        className="fixed inset-0 z-50 flex items-center justify-center bg-black/60"
        role="button"
        tabIndex={0}
        onClick={onClose}
        onKeyDown={(e) => { if (e.key === 'Enter' || e.key === 'Escape') onClose() }}
        aria-label="Close modal"
      >
        <div
          className="w-full max-w-2xl rounded-2xl border border-slate-200 bg-white p-6 shadow-xl"
          onClick={(e) => e.stopPropagation()}
          onKeyDown={(e) => e.stopPropagation()}
        >
          <div className="text-center">
            <div
              className={`mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full ${
                result.failed_count > 0 ? 'bg-amber-100' : 'bg-green-100'
              }`}
            >
              <svg
                className={result.failed_count > 0 ? 'text-amber-600' : 'text-green-600'}
                style={{ width: 40, height: 40 }}
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d={result.failed_count > 0 ? 'M12 8v4m0 4h.01m-7.938 4h15.876c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L2.34 17c-.77 1.333.192 3 1.732 3z' : 'M5 13l4 4L19 7'}
                />
              </svg>
            </div>

            <h2 className="mb-2 text-2xl font-semibold text-slate-900">
              {result.failed_count > 0 ? 'Bulk deletion finished with issues' : 'All companies deleted'}
            </h2>

            <div className="mb-6 rounded-xl border border-blue-200 bg-blue-50 p-4 text-left">
              <h3 className="mb-2 font-semibold text-blue-900">Summary</h3>
              <ul className="list-disc space-y-1 pl-5 text-sm text-blue-800">
                <li><strong>{result.total || 0}</strong> companies targeted</li>
                <li><strong>{result.deleted_count || 0}</strong> companies deleted</li>
                <li><strong>{result.failed_count || 0}</strong> failed deletions</li>
              </ul>
            </div>

            {Array.isArray(result.failed) && result.failed.length > 0 && (
              <div className="mb-6 max-h-44 overflow-auto rounded-xl border border-amber-200 bg-amber-50 p-4 text-left">
                <h3 className="mb-2 font-semibold text-amber-900">Failures</h3>
                <ul className="list-disc space-y-1 pl-5 text-xs text-amber-800">
                  {result.failed.slice(0, 10).map((f, idx) => (
                    <li key={`${f.tenant_id}-${idx}`}>
                      {f.name || f.tenant_id}: {f.detail || 'Unknown error'}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            <button
              onClick={onClose}
              className="w-full rounded-lg bg-blue-600 px-4 py-2.5 text-sm font-semibold text-white transition hover:bg-blue-700"
            >
              Close
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/60"
      role="button"
      tabIndex={0}
      onClick={onClose}
      onKeyDown={(e) => { if (e.key === 'Enter' || e.key === 'Escape') onClose() }}
      aria-label="Close modal"
    >
      <div
        className="w-full max-w-2xl rounded-2xl border border-slate-200 bg-white p-6 shadow-xl"
        onClick={(e) => e.stopPropagation()}
        onKeyDown={(e) => e.stopPropagation()}
      >
        <div className="mb-4 flex items-start gap-4">
          <div className="flex h-12 w-12 items-center justify-center rounded-full bg-red-100">
            <svg className="text-red-600" style={{ width: 24, height: 24 }} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <div className="flex-1">
            <h2 className="mb-1 text-xl font-semibold text-slate-900">Delete all companies</h2>
            <p className="text-sm text-slate-600">
              This action is <strong className="text-red-600">IRREVERSIBLE</strong> and will delete all tenant data.
            </p>
          </div>
        </div>

        <div className="mb-4 rounded-xl border border-red-200 bg-red-50 p-4">
          <h3 className="mb-2 font-semibold text-red-900">Impact</h3>
          <ul className="list-disc space-y-1 pl-5 text-sm text-red-800">
            <li><strong>{companyCount}</strong> companies will be deleted</li>
            <li>Users, products, invoices, clients, modules and roles will be removed</li>
            <li>Audit records are preserved for traceability</li>
          </ul>
        </div>

        <div className="mb-4">
          <label className="mb-2 block text-sm font-medium text-slate-700">
            Type <span className="font-mono">{CONFIRM_TEXT}</span> to confirm:
          </label>
          <input
            type="text"
            value={confirmText}
            onChange={(e) => {
              setConfirmText(e.target.value)
              setError(null)
            }}
            placeholder={CONFIRM_TEXT}
            className="w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-red-500"
          />
          {error && <p className="mt-1 text-xs text-red-600">{error}</p>}
        </div>

        <div className="flex gap-3">
          <button
            type="button"
            onClick={onClose}
            disabled={loading}
            className="flex-1 rounded-lg border border-slate-300 bg-white px-4 py-2 text-sm font-semibold text-slate-700 transition hover:bg-slate-50 disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={() => { void handleSubmit() }}
            disabled={loading || confirmText.trim().toUpperCase() !== CONFIRM_TEXT}
            className="flex-1 rounded-lg bg-red-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-red-700 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {loading ? 'Deleting all...' : 'Delete all companies'}
          </button>
        </div>
      </div>
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import api from '../utils/axios'

export interface SectorTemplate {
  id: number
  name: string
  branding: {
    color_primario: string
    color_secundario?: string
    plantilla_inicio: string
    icon?: string
  }
  modules_count: number
  categories: string[]
  currency: string
}

interface SectorPlantillaSelectorProps {
  value: number | null
  onChange: (sectorId: number | null) => void
  disabled?: boolean
  onTemplateSelected?: (template: SectorTemplate | null) => void
}

export const SectorPlantillaSelector: React.FC<SectorPlantillaSelectorProps> = ({
  value,
  onChange,
  disabled = false,
  onTemplateSelected,
}) => {
  const [templates, setTemplates] = useState<SectorTemplate[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    const fetchTemplates = async () => {
      try {
        setLoading(true)
        const response = await api.get('/v1/sectors/')
        setTemplates(response.data.templates || [])
        setError(null)
      } catch (err: any) {
        console.error('Error fetching sector templates:', err)
        setError(err.response?.data?.detail || 'Error cargando plantillas de sector')
      } finally {
        setLoading(false)
      }
    }

    fetchTemplates()
  }, [])

  const handleSelect = (id: number) => {
    if (disabled) return
    const nextValue = value === id ? null : id
    onChange(nextValue)
    if (onTemplateSelected) {
      const template = templates.find((tpl) => tpl.id === id) || null
      onTemplateSelected(nextValue ? template : null)
    }
  }

  const getIcon = (template: SectorTemplate) => template.branding?.icon || '🏢'

  if (loading) {
    return (
      <div className="sector-selector-loading">
        <div className="spinner"></div>
        <p>Cargando plantillas de sector...</p>
      </div>
    )
  }

  if (error) {
    return (
      <div className="sector-selector-error">
        <p style={{ color: '#dc2626' }}>⚠️ {error}</p>
        <button onClick={() => window.location.reload()}>Reintentar</button>
      </div>
    )
  }

  return (
    <div className="sector-plantilla-selector">
      <div className="sector-header">
        <h3>Tipo de negocio *</h3>
        <p className="sector-description">Elige una base y sigue. El resto se puede ajustar después.</p>
      </div>

      <div className="templates-grid">
        {templates.map((template) => {
          const isSelected = value === template.id

          return (
            <button
              key={template.id}
              type="button"
              className={`template-card ${isSelected ? 'selected' : ''} ${disabled ? 'disabled' : ''}`}
              onClick={() => handleSelect(template.id)}
              style={{
                borderColor: isSelected ? template.branding.color_primario : '#e5e7eb',
                backgroundColor: isSelected ? `${template.branding.color_primario}08` : '#fff',
                cursor: disabled ? 'not-allowed' : 'pointer',
                opacity: disabled ? 0.6 : 1,
              }}
            >
              <div
                className="template-icon"
                style={{
                  background: `linear-gradient(135deg, ${template.branding.color_primario}, ${template.branding.color_primario}dd)`,
                  color: '#fff',
                }}
              >
                <span>{getIcon(template)}</span>
              </div>

              <div className="template-content">
                <div className="template-head">
                  <h4>{template.name}</h4>
                  {isSelected && <div className="selected-indicator">✓</div>}
                </div>
                <div className="template-stats">
                  <span className="stat">
                    <strong>{template.categories.length}</strong> categorías
                  </span>
                  {template.currency && <span className="stat">{template.currency}</span>}
                </div>
                <div className="template-categories" title={template.categories.join(', ')}>
                  <small>{template.categories.slice(0, 3).join(', ')}</small>
                  {template.categories.length > 3 && <small className="more">+{template.categories.length - 3}</small>}
                </div>
                <div className="template-color-badges">
                  <div className="template-color-badge" style={{ backgroundColor: template.branding.color_primario }}>
                    {template.branding.color_primario}
                  </div>
                  {template.branding.color_secundario && (
                    <div className="template-color-badge dark" style={{ backgroundColor: template.branding.color_secundario }}>
                      {template.branding.color_secundario}
                    </div>
                  )}
                </div>
              </div>
            </button>
          )
        })}
      </div>

      <style>{`
        .sector-plantilla-selector {
          margin: 6px 0 0;
        }

        .sector-header {
          margin-bottom: 10px;
        }

        .sector-header h3 {
          margin: 0 0 4px 0;
          font-size: 15px;
          font-weight: 600;
          color: #111827;
        }

        .sector-description {
          margin: 0;
          font-size: 12px;
          color: #6b7280;
        }

        .templates-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
          gap: 10px;
        }

        .template-card {
          position: relative;
          display: grid;
          grid-template-columns: 44px minmax(0, 1fr);
          gap: 10px;
          align-items: start;
          width: 100%;
          padding: 12px;
          border: 1px solid #e5e7eb;
          border-radius: 12px;
          transition: all 0.18s ease;
          text-align: left;
        }

        .template-card:not(.disabled):hover {
          transform: translateY(-1px);
          box-shadow: 0 3px 10px rgba(15, 23, 42, 0.08);
        }

        .template-card.selected {
          border-width: 2px;
          box-shadow: 0 4px 12px rgba(15, 23, 42, 0.08);
        }

        .template-icon {
          width: 44px;
          height: 44px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          box-shadow: 0 4px 10px rgba(0, 0, 0, 0.12);
          font-size: 20px;
        }

        .template-content {
          min-width: 0;
        }

        .template-head {
          display: flex;
          align-items: flex-start;
          justify-content: space-between;
          gap: 8px;
        }

        .template-content h4 {
          margin: 0 0 4px 0;
          font-size: 14px;
          font-weight: 600;
          line-height: 1.25;
          color: #111827;
        }

        .template-stats {
          display: flex;
          flex-wrap: wrap;
          gap: 6px 10px;
          margin-bottom: 4px;
        }

        .stat {
          font-size: 11px;
          color: #6b7280;
        }

        .stat strong {
          color: #111827;
          font-weight: 700;
        }

        .template-categories {
          font-size: 11px;
          color: #9ca3af;
          margin-bottom: 8px;
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }

        .template-categories .more {
          margin-left: 4px;
          color: #6b7280;
          font-weight: 700;
        }

        .template-color-badges {
          display: flex;
          gap: 6px;
          flex-wrap: wrap;
        }

        .template-color-badge {
          display: inline-block;
          padding: 3px 8px;
          border-radius: 999px;
          color: #fff;
          font-size: 10px;
          font-family: monospace;
          font-weight: 700;
        }

        .selected-indicator {
          width: 18px;
          height: 18px;
          background: #10b981;
          color: #fff;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 11px;
          font-weight: 700;
          flex-shrink: 0;
        }

        .sector-selector-loading,
        .sector-selector-error {
          text-align: center;
          padding: 28px;
        }

        .spinner {
          width: 30px;
          height: 30px;
          margin: 0 auto 10px;
          border: 3px solid #f3f4f6;
          border-top-color: #3b82f6;
          border-radius: 50%;
          animation: spin 1s linear infinite;
        }

        @keyframes spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  )
}

export default SectorPlantillaSelector

import React, { useCallback, useEffect, useState } from 'react'

import { useSearchParams } from 'react-router-dom'

import api from '../../services/api'

type FieldItem = { field: string; visible: boolean; required: boolean; ord?: number | null; label?: string | null; help?: string | null; field_type?: string | null; options?: string[] | null; validation_pattern?: string | null }

export default function FieldConfigManager() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [sector, setSector] = useState(searchParams.get('sector') || 'global')
  const [moduleKey, setModuleKey] = useState(searchParams.get('module') || 'clientes')
  const [empresa, setEmpresa] = useState(searchParams.get('empresa') || '')
  const [formMode, setFormMode] = useState<'mixed'|'tenant'|'sector'|'basic'>((searchParams.get('mode') as any) || 'mixed')
  const [items, setItems] = useState<FieldItem[]>([])
  const [loading, setLoading] = useState(false)
  const [msg, setMsg] = useState<string | null>(null)

  const load = useCallback(async () => {
    setMsg(null)
    setLoading(true)
    try {
      // Prefer tenant config when empresa slug is present; otherwise sector defaults
      if (empresa) {
        const { data } = await api.get(`/company/settings/fields`, { params: { module: moduleKey, empresa } })
        setItems(data.items || [])
      } else {
        const { data } = await api.get(`/admin/field-config/sector`, { params: { module: moduleKey, sector } })
        setItems(data.items || [])
      }
    } catch (e: any) {
      setMsg(e?.message || 'Error cargando configuración')
    } finally {
      setLoading(false)
    }
  }, [empresa, moduleKey, sector])

  async function save() {
    setMsg(null)
    setLoading(true)
    try {
      if (empresa) {
        await api.put(`/admin/field-config/tenant`, { empresa, module: moduleKey, items })
        await api.put(`/admin/field-config/tenant/mode`, { empresa, module: moduleKey, form_mode: formMode })
      } else {
        await api.put(`/admin/field-config/sector`, { sector, module: moduleKey, items })
      }
      setMsg('Configuration saved')
    } catch (e: any) {
      setMsg(e?.message || 'Error guardando configuración')
    } finally {
      setLoading(false)
    }
  }

  // Auto-apply query param changes
  useEffect(() => {
    const sp = new URLSearchParams()
    if (sector) sp.set('sector', sector)
    if (moduleKey) sp.set('module', moduleKey)
    if (empresa) sp.set('empresa', empresa)
    if (formMode) sp.set('mode', formMode)
    setSearchParams(sp, { replace: true })
  }, [sector, moduleKey, empresa, formMode, setSearchParams])

  // Auto-load when selection changes
  useEffect(() => { void load() }, [load])

  return (
    <div style={{ padding: 16 }}>
      <h2 style={{ marginTop: 0 }}>Configuración de Campos</h2>
      <p className="text-sm text-slate-500">Gestiona visibilidad y obligatoriedad por sector o por tenant.</p>

      <div style={{ display: 'flex', gap: 12, alignItems: 'end', marginBottom: 12 }}>
        <div>
          <label htmlFor="sector-select">Sector</label>
          <select id="sector-select" name="sector" value={sector} onChange={(e) => setSector(e.target.value)} className="input">
            <option value="global">Global (plantillas base)</option>
            <option value="retail">Retail/Bazar</option>
            <option value="panaderia">Panadería</option>
            <option value="taller">Taller</option>
            <option value="restaurante">Restaurante</option>
            <option value="farmacia">Farmacia</option>
          </select>
        </div>
        <div>
          <label>Módulo</label>
          <select id="module-select" name="module" aria-label="Module" value={moduleKey} onChange={(e) => setModuleKey(e.target.value)} className="input">
            <option value="clientes">Clientes</option>
            <option value="products">Productos</option>
            <option value="inventory">Inventario</option>
            <option value="ventas">Ventas</option>
            <option value="suppliers">Proveedores</option>
            <option value="expenses">Gastos</option>
            <option value="billing">Facturación</option>
            <option value="purchases">Compras</option>
            <option value="crm_leads">CRM Leads</option>
            <option value="crm_opportunities">CRM Oportunidades</option>
          </select>
        </div>
        <div>
          <label htmlFor="empresa-input">Empresa (slug) opcional</label>
          <input id="empresa-input" name="empresa" aria-label="Empresa (slug) opcional" value={empresa} onChange={(e)=> setEmpresa(e.target.value)} placeholder="bazar-omar" className="input" />
        </div>
        <div>
          <label>Modo</label>
          <select aria-label="Modo" value={formMode} onChange={(e)=> setFormMode(e.target.value as any)} className="input">
            <option value="mixed">Mixto (sector + tenant)</option>
            <option value="tenant">Solo tenant (100% personalizado)</option>
            <option value="sector">Solo sector</option>
            <option value="basic">Básico</option>
          </select>
        </div>
        <button className="gc-button gc-button--primary" onClick={() => { void save() }} disabled={loading}>Guardar</button>
      </div>

      {msg && <div className="notice">{msg}</div>}

      {loading ? (
        <div>Cargando…</div>
      ) : (
        <table className="min-w-full text-sm">
          <thead>
            <tr>
              <th>Campo</th>
              <th>Visible</th>
              <th>Obligatorio</th>
              <th>Orden</th>
              <th>Etiqueta</th>
              <th>Ayuda</th>
              <th>Tipo</th>
              <th>Opciones</th>
              <th>Patrón</th>
              <th>✕</th>
            </tr>
          </thead>
          <tbody>
            {items.map((it, i) => (
              <tr key={i}>
                <td><input aria-label={`Campo fila ${i+1}`} name={`field-${i}`} value={it.field} onChange={(e)=> {
                  const v = e.target.value; setItems(prev => prev.map((x,idx)=> idx===i? {...x, field: v}: x))
                }} className="input" /></td>
                <td><input aria-label={`Visible fila ${i+1}`} name={`visible-${i}`} type="checkbox" checked={!!it.visible} onChange={(e)=> setItems(prev => prev.map((x,idx)=> idx===i? {...x, visible: e.target.checked}: x))} /></td>
                <td><input aria-label={`Obligatorio fila ${i+1}`} name={`required-${i}`} type="checkbox" checked={!!it.required} onChange={(e)=> setItems(prev => prev.map((x,idx)=> idx===i? {...x, required: e.target.checked}: x))} /></td>
                <td><input aria-label={`Orden fila ${i+1}`} name={`ord-${i}`} type="number" value={it.ord ?? ''} onChange={(e)=> {
                  const num = e.target.value === '' ? null : Number(e.target.value);
                  setItems(prev => prev.map((x,idx)=> idx===i? {...x, ord: (num as any)}: x))
                }} className="input" style={{ width: 80 }} /></td>
                <td><input aria-label={`Etiqueta fila ${i+1}`} name={`label-${i}`} value={it.label || ''} onChange={(e)=> setItems(prev => prev.map((x,idx)=> idx===i? {...x, label: e.target.value}: x))} className="input" /></td>
                <td><input aria-label={`Ayuda fila ${i+1}`} name={`help-${i}`} value={it.help || ''} onChange={(e)=> setItems(prev => prev.map((x,idx)=> idx===i? {...x, help: e.target.value}: x))} className="input" /></td>
                <td>
                  <select
                    aria-label={`Tipo fila ${i+1}`}
                    value={it.field_type || 'text'}
                    onChange={(e) => setItems(prev => prev.map((x, idx) => idx === i ? { ...x, field_type: e.target.value } : x))}
                    className="input"
                  >
                    <option value="text">Texto</option>
                    <option value="number">Número</option>
                    <option value="date">Fecha</option>
                    <option value="boolean">Sí/No</option>
                    <option value="select">Desplegable</option>
                    <option value="textarea">Texto largo</option>
                    <option value="email">Email</option>
                  </select>
                </td>
                <td>
                  <input
                    aria-label={`Opciones fila ${i+1}`}
                    value={(it.options || []).join(', ')}
                    onChange={(e) => {
                      const opts = e.target.value.split(',').map(s => s.trim()).filter(Boolean)
                      setItems(prev => prev.map((x, idx) => idx === i ? { ...x, options: opts } : x))
                    }}
                    className="input"
                    placeholder="op1, op2, op3"
                    disabled={it.field_type !== 'select'}
                    style={{ width: 160 }}
                  />
                </td>
                <td>
                  <input
                    aria-label={`Patrón fila ${i+1}`}
                    value={it.validation_pattern || ''}
                    onChange={(e) => setItems(prev => prev.map((x, idx) => idx === i ? { ...x, validation_pattern: e.target.value } : x))}
                    className="input"
                    placeholder="^[0-9]+$"
                    style={{ width: 140 }}
                  />
                </td>
                <td>
                  <button
                    type="button"
                    aria-label={`Eliminar fila ${i+1}`}
                    onClick={() => setItems(prev => prev.filter((_, idx) => idx !== i))}
                    style={{ color: '#ef4444', background: 'none', border: 'none', cursor: 'pointer', fontSize: 18 }}
                    title="Eliminar campo"
                  >✕</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      <div style={{ marginTop: 12 }}>
        <button className="gc-button" onClick={()=> setItems(prev => [...prev, { field: '', visible: true, required: false, field_type: 'text' }])}>Añadir campo</button>
      </div>
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import api from '../../services/api'

type ImportedField = {
  field: string
  visible: boolean
  required: boolean
  ord?: number | null
  field_type?: string | null
}

type TableOption = { table: string; module: string }

export default function ImportCatalog() {
  const [sector, setSector] = useState('global')
  const [tableOptions, setTableOptions] = useState<TableOption[]>([])
  const [tableName, setTableName] = useState<string>('')
  const [moduleName, setModuleName] = useState<string>('')
  const [loading, setLoading] = useState(false)
  const [msg, setMsg] = useState<string | null>(null)
  const [fields, setFields] = useState<ImportedField[]>([])
  const [loadError, setLoadError] = useState<string | null>(null)

  useEffect(() => {
    async function loadTables() {
      try {
        const { data } = await api.get('/admin/field-config/import-tables')
        const items: TableOption[] = data.items || []
        setTableOptions(items)
        if (items.length > 0) {
          setTableName(items[0].table)
          setModuleName(items[0].module)
          setLoadError(null)
        } else {
          setLoadError('No hay tablas disponibles. Revisa permisos o whitelist.')
        }
      } catch (e: any) {
        setLoadError(e?.message || 'No se pudieron cargar las tablas disponibles.')
      }
    }
    void loadTables()
  }, [])

  useEffect(() => {
    const found = tableOptions.find((t) => t.table === tableName)
    if (found) {
      setModuleName(found.module)
    } else if (tableName) {
      setModuleName(`imports_${tableName}`)
    } else {
      setModuleName('')
    }
  }, [tableName, tableOptions])

  const doImport = async () => {
    setLoading(true)
    setMsg(null)
    try {
      const { data } = await api.post('/admin/field-config/import-table', {
        table: tableName,
        module: moduleName,
        sector,
      })
      setFields(data.items || [])
      setMsg(`Importadas columnas de ${tableName} → ${moduleName}`)
    } catch (e: any) {
      setMsg(e?.message || 'No se pudo importar la tabla (ver whitelist backend).')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{ padding: 16 }}>
      <h2 style={{ marginTop: 0 }}>Importar catálogo de campos</h2>
      <p className="text-sm text-slate-500">
        Carga los campos base desde tablas permitidas y guárdalos como catálogo global (sector_global).
      </p>
      <div style={{ display: 'flex', gap: 12, alignItems: 'end', marginBottom: 12, flexWrap: 'wrap' }}>
        <div>
          <label htmlFor="import-sector-select">Sector</label>
          <select id="import-sector-select" className="input" value={sector} onChange={(e) => setSector(e.target.value)}>
            <option value="global">Global (plantillas base)</option>
            <option value="retail">Retail</option>
            <option value="panaderia">Panadería</option>
            <option value="restaurante">Restaurante</option>
            <option value="taller">Taller</option>
            <option value="farmacia">Farmacia</option>
          </select>
        </div>
        <div>
          <label htmlFor="import-table-select">Tabla origen (whitelist)</label>
          <select id="import-table-select" className="input" value={tableName} onChange={(e) => setTableName(e.target.value)}>
            {tableOptions.map((t) => (
              <option key={t.table} value={t.table}>{t.table}</option>
            ))}
          </select>
        </div>
        <div>
          <label>Módulo destino</label>
          <input className="input" value={moduleName} readOnly disabled />
        </div>
        <button className="gc-button gc-button--primary" onClick={() => { void doImport() }} disabled={loading}>
          {loading ? 'Importando…' : 'Importar'}
        </button>
      </div>
      {loadError && <div className="notice" style={{ marginBottom: 12 }}>{loadError}</div>}
      {msg && <div className="notice" style={{ marginBottom: 12 }}>{msg}</div>}

      {fields.length > 0 && (
        <table className="min-w-full text-sm">
          <thead>
            <tr>
              <th>Campo</th>
              <th>Obligatorio</th>
              <th>Tipo</th>
              <th>Orden</th>
            </tr>
          </thead>
          <tbody>
            {fields.map((f, idx) => (
              <tr key={idx}>
                <td>{f.field}</td>
                <td>{f.required ? 'Sí' : 'No'}</td>
                <td>{f.field_type || 'string'}</td>
                <td>{f.ord ?? ''}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import { useNavigate, useParams } from 'react-router-dom'

import { createCategoriaGasto, getCategoriaGasto, updateCategoriaGasto, type CategoriaGasto as CategoriaGastoT } from '../../../services/configuracion/categorias-gasto'
import { useToast, getErrorMessage } from '../../../shared/toast'

type FormT = Omit<CategoriaGastoT, 'id'>

export default function CategoriaGastoForm() {
  const { id } = useParams()
  const nav = useNavigate()
  const [form, setForm] = useState<FormT>({ code: '', name: '', parent_code: '', active: true })
  const { success, error } = useToast()
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (id) {
      setLoading(true)
      getCategoriaGasto(id)
        .then((m) => setForm({ code: m.code, name: m.name, parent_code: m.parent_code, active: m.active }))
        .catch((e) => error(getErrorMessage(e)))
        .finally(() => setLoading(false))
    }
  }, [id])

  const onSubmit: React.FormEventHandler = async (e) => {
    e.preventDefault()
    try {
      if (!form.code?.trim() || !form.name?.trim()) throw new Error('Complete código y nombre')
      if (id) await updateCategoriaGasto(id, form)
      else await createCategoriaGasto(form)
      success('Categoría de gasto guardada')
      nav('..')
    } catch (e:any) {
      error(getErrorMessage(e))
    }
  }

  return (
    <div style={{ padding: 16 }}>
      <h3 className="text-xl font-semibold mb-3">{id ? 'Editar Categoría de gasto' : 'Nueva Categoría de gasto'}</h3>
