          <thead><tr><th>Código</th><th>Nombre</th><th>Activo</th><th></th></tr></thead>
          <tbody>
            {items.length === 0 && <tr><td colSpan={4}>Sin locales</td></tr>}
            {items.map((it) => (
              <tr key={it.code}>
                <td>{it.code}</td>
                <td>{it.name}</td>
