import React, { useEffect, useState } from 'react'

import { useNavigate, useParams } from 'react-router-dom'

import { createPermiso, getPermiso, updatePermiso } from '../../../services/configuracion/permisos'
import { useToast, getErrorMessage } from '../../../shared/toast'

type FormT = { key: string; module: string; description: string }

export default function PermisoForm() {
  const { id } = useParams()
  const nav = useNavigate()
  const [form, setForm] = useState<FormT>({ key: '', module: '', description: '' })
  const { success, error } = useToast()

  useEffect(() => {
    if (id) {
      getPermiso(id)
        .then((p) => setForm({ key: p.key, module: p.module || '', description: p.description || '' }))
        .catch(() => {})
    }
  }, [id])

  const isValid = !!form.module?.trim() && !!form.key?.trim() && !!form.description?.trim()

  const onSubmit: React.FormEventHandler = async (e) => {
    e.preventDefault()
    try {
      if (!form.module?.trim()) throw new Error('El módulo es obligatorio')
      if (!form.key?.trim()) throw new Error('El key es obligatorio')
      const payload = {
        key: form.key.trim(),
        module: form.module.trim(),
        description: form.description.trim(),
      }
      if (id) await updatePermiso(id, payload)
      else await createPermiso(payload)
      success('Permiso guardado')
      nav('..')
    } catch (e: any) {
      error(getErrorMessage(e))
    }
  }

  return (
    <div style={{ padding: 16 }}>
      <h3 className="text-xl font-semibold mb-3">{id ? 'Editar permiso' : 'Nuevo permiso'}</h3>
      <form onSubmit={onSubmit} className="space-y-4" style={{ maxWidth: 520 }}>
        <div>
          <label className="block mb-1">Módulo</label>
          <input
            value={form.module || ''}
            onChange={(e) => setForm({ ...form, module: e.target.value })}
            className="border px-2 py-1 w-full rounded"
            placeholder="pos"
            required
          />
        </div>
        <div>
          <label className="block mb-1">Key</label>
          <input
            value={form.key}
            onChange={(e) => setForm({ ...form, key: e.target.value })}
            className="border px-2 py-1 w-full rounded"
            placeholder="pos.receipt.pay"
            required
          />
          <p className="text-xs text-gray-500 mt-1">Usa prefijo por módulo, ej: pos.*, sales.*</p>
        </div>
        <div>
          <label className="block mb-1">Descripción</label>
          <input
            value={form.description || ''}
            onChange={(e) => setForm({ ...form, description: e.target.value })}
            className="border px-2 py-1 w-full rounded"
            required
          />
        </div>
        <div className="pt-2">
          <button type="submit" className="bg-blue-600 text-white px-3 py-2 rounded disabled:opacity-50" disabled={!isValid}>Guardar</button>
          <button type="button" className="ml-3 px-3 py-2" onClick={() => nav('..')}>Cancelar</button>
        </div>
      </form>
    </div>
  )
}

import React, { useEffect, useMemo, useState } from 'react'

import { Link, useNavigate } from 'react-router-dom'

import {
  createPermiso,
  listPermisos,
  removePermiso,
  type GlobalPermission,
} from '../../../services/configuracion/permisos'
import { listModulos } from '../../../services/modulos'

const BASIC_PERMISSION_DEFS = [
  { action: 'read', description: 'Ver' },
  { action: 'create', description: 'Crear' },
  { action: 'update', description: 'Editar' },
  { action: 'delete', description: 'Eliminar' },
] as const

function moduleFromPermission(item: GlobalPermission): string {
  if (item.module) return item.module
  const parts = (item.key || '').split('.')
  return parts.length > 1 ? parts[0] : 'general'
}

function normalizeModuleSlug(raw?: string | null): string | null {
  const value = (raw || '').trim().toLowerCase()
  if (!value) return null

  if (value.includes('/')) {
    const parts = value.split('/').filter(Boolean)
    return parts.at(-1) || null
  }

  return value
}

function getModulePermissionSlug(module: { name?: string | null; url?: string | null }): string | null {
  return normalizeModuleSlug(module.url) || normalizeModuleSlug(module.name)
}

export default function PermisosList() {
  const [items, setItems] = useState<GlobalPermission[]>([])
  const [loading, setLoading] = useState(false)
  const [creatingBasics, setCreatingBasics] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [feedback, setFeedback] = useState<string | null>(null)
  const [moduleFilter, setModuleFilter] = useState('all')
  const nav = useNavigate()

  useEffect(() => {
    ;(async () => {
      try {
        setLoading(true)
        setItems(await listPermisos())
      } catch (e: any) {
        setError(e?.response?.data?.detail || e?.message || 'No se pudieron cargar los permisos')
      } finally {
        setLoading(false)
      }
    })()
  }, [])

  const handleCreateBasicPermissions = async () => {
    try {
      setCreatingBasics(true)
      setError(null)
      setFeedback(null)

      const [modules, permissions] = await Promise.all([listModulos(), listPermisos()])
      const existingKeys = new Set(permissions.map((item) => item.key))
      const moduleSlugs = Array.from(
        new Set(
          modules
            .map((module) => getModulePermissionSlug(module))
            .filter((slug): slug is string => Boolean(slug))
        )
      ).sort()

      const missing = moduleSlugs.flatMap((module) =>
        BASIC_PERMISSION_DEFS
          .map(({ action, description }) => ({
            module,
            key: `${module}.${action}`,
            description: `${description} ${module}`,
          }))
          .filter((permission) => !existingKeys.has(permission.key))
      )

      if (missing.length === 0) {
        setFeedback('No faltaban permisos básicos por crear.')
        return
      }

      const failures: string[] = []

      for (const permission of missing) {
        try {
          await createPermiso(permission)
        } catch (e: any) {
          failures.push(
            `${permission.key}: ${e?.response?.data?.detail || e?.message || 'error desconocido'}`
          )
        }
      }

      setItems(await listPermisos())
      setFeedback(`Se crearon ${missing.length - failures.length} permisos básicos.`)
      if (failures.length > 0) {
        setError(failures.slice(0, 3).join(' | '))
      }
    } finally {
      setCreatingBasics(false)
    }
  }

  const modules = useMemo(() => {
    const set = new Set(items.map((it) => moduleFromPermission(it)))
    return ['all', ...Array.from(set).sort()]
  }, [items])

  const filtered = useMemo(() => {
    if (moduleFilter === 'all') return items
    return items.filter((it) => moduleFromPermission(it) === moduleFilter)
  }, [items, moduleFilter])

  return (
    <div style={{ padding: 16 }}>
      <div className="mb-3 flex items-center justify-between">
        <h3 className="text-xl font-semibold">Permisos globales</h3>
        <div className="flex items-center gap-2">
          <button
            className="rounded bg-emerald-600 px-3 py-1 text-white disabled:opacity-60"
            onClick={handleCreateBasicPermissions}
            disabled={creatingBasics}
          >
            {creatingBasics ? 'Creando básicos...' : 'Crear básicos'}
          </button>
          <button className="rounded bg-blue-600 px-3 py-1 text-white" onClick={() => nav('nuevo')}>
            Nuevo
          </button>
        </div>
      </div>
      <div className="mb-3 flex items-center gap-3">
        <label className="text-sm text-gray-600">Módulo</label>
        <select
          value={moduleFilter}
          onChange={(e) => setModuleFilter(e.target.value)}
          className="rounded border px-2 py-1"
        >
          {modules.map((m) => (
            <option key={m} value={m}>
              {m}
            </option>
          ))}
        </select>
      </div>
      {loading && <div className="text-sm text-gray-500">Cargando</div>}
      {error && <div className="mb-3 rounded bg-red-100 px-3 py-2 text-red-700">{error}</div>}
      {feedback && (
        <div className="mb-3 rounded bg-emerald-100 px-3 py-2 text-emerald-700">{feedback}</div>
      )}
      <table className="min-w-full rounded border border-gray-200 bg-white">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-3 py-2 text-left">Módulo</th>
            <th className="px-3 py-2 text-left">Key</th>
            <th className="px-3 py-2 text-left">Descripción</th>
            <th className="px-3 py-2 text-left">Acciones</th>
          </tr>
        </thead>
        <tbody>
          {filtered.map((it) => (
            <tr key={it.id} className="border-t">
              <td className="px-3 py-2">{moduleFromPermission(it)}</td>
              <td className="px-3 py-2">{it.key}</td>
              <td className="px-3 py-2">{it.description || '-'}</td>
              <td className="px-3 py-2">
                <Link to={`${it.id}/editar`} className="mr-3 text-blue-600 hover:underline">
                  Editar
                </Link>
                <button
                  className="text-red-700"
                  onClick={async () => {
                    if (!confirm('Eliminar permiso?')) return
                    await removePermiso(it.id)
                    setItems((prev) => prev.filter((x) => x.id !== it.id))
                  }}
                >
                  Eliminar
                </button>
              </td>
            </tr>
          ))}
          {!loading && filtered.length === 0 && (
            <tr>
              <td className="px-3 py-3" colSpan={4}>
                Sin permisos
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  )
}

import React, { useState } from 'react';

import { useNavigate } from 'react-router-dom';
import { toast, ToastContainer } from 'react-toastify';

import 'react-toastify/dist/ReactToastify.css';
import { permisosToArray } from '@shared/utils/permissions';

import { apiPost, apiPut } from '../../../lib/api';

import type { RoleData } from './types/roles';
import type { GlobalPermission } from '../../../services/configuracion/permisos';

// Layout no es necesario: ya hay LayoutAdmin en App

interface RoleFormProps {
  mode: 'create' | 'edit';
  initialData?: RoleData;
  onSubmit: (data: RoleData) => void;
  availablePermissions: GlobalPermission[];
}

const RoleForm: React.FC<RoleFormProps> = ({ mode, initialData, onSubmit, availablePermissions }) => {
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const buildPerms = (perms?: string[]) => {
    const keys = new Set<string>();
    availablePermissions.forEach((p) => keys.add(p.key));
    (perms || []).forEach((p) => keys.add(p));
    return Array.from(keys).reduce((acc, key) => {
      acc[key] = (perms || []).includes(key);
      return acc;
    }, {} as Record<string, boolean>);
  };

  const [form, setForm] = useState({
    nombre: initialData?.nombre || '',
    descripcion: initialData?.descripcion || '',
    permisos: buildPerms(initialData?.permisos),
  });

  const [errors, setErrors] = useState<{ nombre?: string; descripcion?: string }>({});

  React.useEffect(() => {
    setForm((prev) => ({
      ...prev,
      permisos: {
        ...buildPerms(Object.keys(prev.permisos || {}).filter((k) => prev.permisos[k])),
      },
    }));
  }, [availablePermissions]);

  const handleInputChange = (field: 'nombre' | 'descripcion', value: string) => {
    setForm(prev => ({ ...prev, [field]: value }));
  };

  const handlePermissionToggle = (key: string) => {
    setForm(prev => ({
      ...prev,
      permisos: {
        ...prev.permisos,
        [key]: !prev.permisos[key],
      },
    }));
  };

  // Removed "Copiar desde rol base" feature

  const validate = () => {
    const newErrors: typeof errors = {};
    if (!form.nombre.trim()) newErrors.nombre = 'El nombre del rol es obligatorio.';
    if (!form.descripcion.trim()) newErrors.descripcion = 'La descripción es obligatoria.';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async () => {
    if (isSubmitting || !validate()) return;

    setIsSubmitting(true);

    const payload: RoleData = {
      id: initialData?.id,
      nombre: form.nombre.trim(),
      descripcion: form.descripcion.trim(),
      permisos: permisosToArray(form.permisos),
    };

    const endpoint = mode === 'edit'
      ? `/v1/roles-base/${initialData?.id}`
      : '/v1/roles-base/';

    try {
      const savedRole = mode === 'edit'
        ? await apiPut<RoleData>(endpoint, payload)
        : await apiPost<RoleData>(endpoint, payload);

      toast.success(`✅ Rol ${mode === 'edit' ? 'actualizado' : 'creado'} correctamente`);
      onSubmit(savedRole);
      navigate('/admin/configuracion/roles', { replace: true });
    } catch (err: any) {
      toast.error(`❌ ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <ToastContainer />
      <h1 className="text-2xl font-bold mb-6">
        {mode === 'edit' ? '✏️ Editar Rol' : '➕ Crear Rol'}
      </h1>

      {/* Removed: Copiar desde rol base */}

      <div className="mb-4">
        <label className="block font-medium text-sm mb-1">
          Nombre del rol <span className="text-red-600">*</span>
        </label>
        <input
          type="text"
          value={form.nombre}
          onChange={e => handleInputChange('nombre', e.target.value)}
          className="w-full border p-2"
        />
        {errors.nombre && <p className="text-red-600 text-sm mt-1">{errors.nombre}</p>}
      </div>

      <div className="mb-6">
        <label className="block font-medium text-sm mb-1">
          Descripción <span className="text-red-600">*</span>
        </label>
        <input
          type="text"
          value={form.descripcion}
          onChange={e => handleInputChange('descripcion', e.target.value)}
          className="w-full border p-2"
        />
        {errors.descripcion && <p className="text-red-600 text-sm mt-1">{errors.descripcion}</p>}
      </div>

      <fieldset className="mb-6">
        <legend className="text-lg font-semibold mb-2">Permisos disponibles</legend>
        <div className="grid grid-cols-2 gap-2">
          {Array.from(
            new Set([
              ...availablePermissions.map((p) => p.key),
              ...Object.keys(form.permisos || {}),
            ])
          )
            .sort()
            .map((key) => {
              const meta = availablePermissions.find((p) => p.key === key);
              const label = meta?.description ? `${meta.description} (${key})` : key;
              return (
            <div key={key} className="flex items-center gap-2">
              <input
                type="checkbox"
                id={`permiso-${key}`}
                checked={!!form.permisos[key]}
                onChange={() => handlePermissionToggle(key)}
              />
              <label htmlFor={`permiso-${key}`}>{label}</label>
            </div>
              );
            })}
        </div>
      </fieldset>

      <div className="flex gap-4">
        <button
          onClick={handleSubmit}
          disabled={isSubmitting}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded disabled:opacity-50"
        >
          💾 {isSubmitting ? 'Guardando...' : 'Save'}
        </button>
        <button
          onClick={() => navigate(-1)}
          className="bg-gray-500 hover:bg-gray-600 text-white px-4 py-2 rounded"
        >
          Cancelar
        </button>
      </div>
    </div>
  );

};

export default RoleForm;

import React, { useEffect, useState } from 'react';

import { Routes, Route, Navigate } from 'react-router-dom';

import ConfirmDelete from './ConfirmDelete';
import EditWrapper from './EditWrapper';
import RoleForm from './RoleForm';
import RoleList from './RolesList';
import { apiGet, apiPost, apiPut, apiDelete } from '../../../lib/api';
import { listPermisos, type GlobalPermission } from '../../../services/configuracion/permisos';

import type { Role, RoleData, RoleFromBackend } from './types/roles';

const RolesRouter: React.FC = () => {
  const [roles, setRoles] = useState<Role[]>([]);
  const [deleteId, setDeleteId] = useState<number | null>(null);
  const [permissions, setPermissions] = useState<GlobalPermission[]>([]);

  const toPermMap = (perms: string[] | undefined) => {
    const keys = new Set<string>(perms || []);
    permissions.forEach((p) => keys.add(p.key));
    return Array.from(keys).reduce((acc, key) => {
      acc[key] = (perms || []).includes(key);
      return acc;
    }, {} as Record<string, boolean>);
  };

  useEffect(() => {
    apiGet<RoleFromBackend[]>('/v1/roles-base/')
      .then(data => {
        const normalized = data.map(role => ({
          ...role,
          permisos: toPermMap(role.permisos),
        }));
        setRoles(normalized);
      })
      .catch(err => console.error('❌ Error al cargar roles:', err));
    listPermisos()
      .then(setPermissions)
      .catch(err => console.error('❌ Error al cargar permisos:', err));
  }, []);

  useEffect(() => {
    setRoles((prev) =>
      prev.map((role) => ({
        ...role,
        permisos: toPermMap(
          Object.entries(role.permisos || {})
            .filter(([, val]) => val)
            .map(([key]) => key)
        ),
      }))
    );
  }, [permissions]);

  const handleSave = async (roleData: RoleData) => {
    const payload: RoleData = {
      nombre: roleData.nombre,
      descripcion: roleData.descripcion,
      permisos: roleData.permisos,
    };

    try {
      const saved = roleData.id
        ? await apiPut<RoleData>(`/v1/roles-base/${roleData.id}`, payload)
        : await apiPost<RoleData>('/v1/roles-base/', payload);

      const normalized: Role = {
        ...saved,
        permisos: toPermMap(saved.permisos),
        id: saved.id!,
      };

      setRoles(prev =>
        roleData.id
          ? prev.map(r => (r.id === normalized.id ? normalized : r))
          : [...prev, normalized]
      );
    } catch (err) {
      console.error('❌ Error al guardar rol:', err);
    }
  };

  const handleDelete = (id: number) => setDeleteId(id);

  const confirmDelete = async () => {
    if (deleteId !== null) {
      try {
        await apiDelete(`/v1/roles-base/${deleteId}`);
        setRoles(prev => prev.filter(r => r.id !== deleteId));
        setDeleteId(null);
      } catch (err) {
        console.error('❌ Error al eliminar rol:', err);
      }
    }
  };

  // Removed base role copy feature

  return (
    <>
      <Routes>

        <Route index element={<RoleList roles={roles} onDelete={handleDelete} />} />
        <Route
          path="nuevo"
          element={<RoleForm mode="create" onSubmit={handleSave} availablePermissions={permissions} />}
        />
        <Route
          path=":id/editar"
          element={<EditWrapper roles={roles} onSubmit={handleSave} availablePermissions={permissions} />}
        />
      </Routes>

      {deleteId !== null && (
        <ConfirmDelete
          nombre={roles.find(r => r.id === deleteId)?.nombre || ''}
          onConfirm={confirmDelete}
          onCancel={() => setDeleteId(null)}
        />
      )}
    </>
  );
};

export default RolesRouter;

import React, { useEffect, useState } from 'react'

import { useNavigate, useParams } from 'react-router-dom'

import {
  createSector,
  getSector,
  updateSector,
  DEFAULT_TEMPLATE_CONFIG,
  type SectorPayload,
  type SectorTemplateConfig,
  type BrandingConfig,
} from '../../../services/configuracion/sectores'
import { listTipoEmpresa, type TipoEmpresa } from '../../../services/configuracion/tipo-empresa'
import { listTipoNegocio, type TipoNegocio } from '../../../services/configuracion/tipo-negocio'
import { useToast, getErrorMessage } from '../../../shared/toast'

type FormT = SectorPayload
type SelectOption = { id: string; name: string }

const TEMPLATE_OPTIONS = [
  'default',
  'panaderia',
  'panaderia_pro',
  'retail',
  'retail_pro',
  'taller',
  'taller_pro',
  'todoa100',
]

const featureOptions = [
  { key: 'recipes', label: 'Habilitar gestión de recetas' },
  { key: 'bakery_sales_account', label: 'Ingresos bakería' },
  { key: 'inventory_expiry_tracking', label: 'Seguimiento de caducidad' },
  { key: 'inventory_lot_tracking', label: 'Seguimiento de lotes' },
  { key: 'inventory_serial_tracking', label: 'Seguimiento de series' },
  { key: 'loss_account', label: 'Mostrar cuenta pérdidas/mermas' },
]

const ensureTemplateConfig = (cfg?: Partial<SectorTemplateConfig> | null): SectorTemplateConfig => ({
  ...DEFAULT_TEMPLATE_CONFIG,
  ...(cfg || {}),
  features: {
    ...DEFAULT_TEMPLATE_CONFIG.features,
    ...(cfg?.features || {}),
  },
  branding: {
    ...DEFAULT_TEMPLATE_CONFIG.branding,
    ...(cfg?.branding || {}),
  },
  defaults: {
    ...DEFAULT_TEMPLATE_CONFIG.defaults,
    ...(cfg?.defaults || {}),
  },
  pos: { ...DEFAULT_TEMPLATE_CONFIG.pos, ...(cfg?.pos || {}) },
  inventory: { ...DEFAULT_TEMPLATE_CONFIG.inventory, ...(cfg?.inventory || {}) },
})

export default function SectorForm() {
  const { id } = useParams()
  const nav = useNavigate()
  const { success, error } = useToast()
  const [form, setForm] = useState<FormT>({
    name: '',
    code: '',
    description: '',
    template_config: ensureTemplateConfig(),
    active: true,
  })
  const [rawConfig, setRawConfig] = useState(() => JSON.stringify(ensureTemplateConfig(), null, 2))
  const [empresas, setEmpresas] = useState<SelectOption[]>([])
  const [negocios, setNegocios] = useState<SelectOption[]>([])
  const [loadingCatalogs, setLoadingCatalogs] = useState(false)

  useEffect(() => {
    ;(async () => {
      try {
        setLoadingCatalogs(true)
        const [es, ns] = await Promise.all([listTipoEmpresa(), listTipoNegocio()])
        setEmpresas(es)
        setNegocios(ns)
      } catch {
        // Ignore; selects will just be empty
      } finally {
        setLoadingCatalogs(false)
      }
    })()
  }, [])

  useEffect(() => {
    // Pre-fill defaults with first option if none selected
    setForm((prev) => {
      const defaults = prev.template_config.defaults || {}
      const nextDefaults = { ...defaults }
      let changed = false
      if (!defaults.business_type_id && empresas[0]?.id) {
        nextDefaults.business_type_id = empresas[0].id
        changed = true
      }
      if (!defaults.business_category_id && negocios[0]?.id) {
        nextDefaults.business_category_id = negocios[0].id
        changed = true
      }
      if (!changed) return prev
      return {
        ...prev,
        template_config: ensureTemplateConfig({
          ...prev.template_config,
          defaults: nextDefaults,
        }),
      }
    })
  }, [empresas, negocios])

  useEffect(() => {
    if (!id) {
      setForm({
        name: '',
        code: '',
        description: '',
        template_config: ensureTemplateConfig(),
        active: true,
      })
      return
    }
    getSector(id)
      .then((m) => {
        const cfg = ensureTemplateConfig(m.template_config)
        const dashboardTemplate =
          m.template_config?.branding?.dashboard_template ||
          m.template_config?.branding?.plantilla_inicio ||
          cfg.branding.dashboard_template

        setForm({
          name: m.name || '',
          code: m.code || '',
          description: m.description || '',
          template_config: {
            ...cfg,
            branding: {
              ...cfg.branding,
              dashboard_template: dashboardTemplate,
            },
            defaults: {
              ...cfg.defaults,
              business_type_id: cfg.defaults?.business_type_id || '',
              business_category_id: cfg.defaults?.business_category_id || '',
            },
          },
          active: m.active ?? true,
        })
      })
      .catch(() => {})
  }, [id])

  useEffect(() => {
    setRawConfig(JSON.stringify(form.template_config, null, 2))
  }, [form.template_config])

  const updateBranding = (patch: Partial<BrandingConfig>) => {
    setForm((prev) => ({
      ...prev,
      template_config: ensureTemplateConfig({
        ...prev.template_config,
        branding: { ...prev.template_config?.branding, ...patch },
      }),
    }))
  }

  const toggleFeature = (featureKey: string, enabled: boolean) => {
    setForm((prev) => ({
      ...prev,
      template_config: ensureTemplateConfig({
        ...prev.template_config,
        features: {
          ...(prev.template_config.features || {}),
          [featureKey]: enabled,
        },
      }),
    }))
  }

  const onSubmit: React.FormEventHandler = async (e) => {
    e.preventDefault()
    try {
      if (!form.name?.trim()) throw new Error('Name is required')
      let parsedConfig: SectorTemplateConfig
      try {
        parsedConfig = ensureTemplateConfig(JSON.parse(rawConfig))
      } catch {
        throw new Error('Config JSON inválido')
      }

      // Ensure defaults carry business type/category selections
      parsedConfig.defaults = {
        ...parsedConfig.defaults,
        business_type_id: form.template_config.defaults?.business_type_id || '',
        business_category_id: form.template_config.defaults?.business_category_id || '',
      }

      const payload: FormT = {
        name: form.name.trim(),
        code: form.code?.trim() || null,
        description: form.description?.trim() || null,
        template_config: parsedConfig,
        active: form.active ?? true,
      }
      if (id) await updateSector(id, payload)
      else await createSector(payload)
      success('Sector guardado')
      nav('..')
    } catch (e: any) {
      error(getErrorMessage(e))
    }
  }

  const branding = form.template_config?.branding || DEFAULT_TEMPLATE_CONFIG.branding

  return (
    <div style={{ padding: 16 }}>
      <h3 className="text-xl font-semibold mb-3">{id ? 'Editar Sector' : 'Nuevo Sector'}</h3>
      <form onSubmit={onSubmit} className="space-y-4" style={{ maxWidth: 720 }}>
        <div>
          <label className="block mb-1">Nombre</label>
          <input
            value={form.name}
            onChange={(e) => setForm((prev) => ({ ...prev, name: e.target.value }))}
            className="border px-2 py-1 w-full rounded"
            required
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block mb-1">Código (opcional)</label>
            <input
              value={form.code || ''}
              onChange={(e) => setForm((prev) => ({ ...prev, code: e.target.value }))}
              className="border px-2 py-1 w-full rounded"
              placeholder="p.ej. bakery"
            />
          </div>
          <div>
            <label className="block mb-1">Descripción (opcional)</label>
            <input
              value={form.description || ''}
              onChange={(e) => setForm((prev) => ({ ...prev, description: e.target.value }))}
              className="border px-2 py-1 w-full rounded"
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block mb-1">Tipo de Empresa</label>
            <select
              value={form.template_config.defaults?.business_type_id || ''}
              onChange={(e) =>
                setForm((prev) => ({
                  ...prev,
                  template_config: ensureTemplateConfig({
                    ...prev.template_config,
                    defaults: {
                      ...prev.template_config.defaults,
                      business_type_id: e.target.value,
                    },
                  }),
                }))
              }
              className="border px-2 py-1 w-full rounded"
            >
              <option value="">Sin seleccionar</option>
              {empresas.map((x) => (
                <option key={x.id} value={x.id}>
                  {x.name}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label className="block mb-1">Tipo de Negocio</label>
            <select
              value={form.template_config.defaults?.business_category_id || ''}
              onChange={(e) =>
                setForm((prev) => ({
                  ...prev,
                  template_config: ensureTemplateConfig({
                    ...prev.template_config,
                    defaults: {
                      ...prev.template_config.defaults,
                      business_category_id: e.target.value,
                    },
                  }),
                }))
              }
              className="border px-2 py-1 w-full rounded"
            >
              <option value="">Sin seleccionar</option>
              {negocios.map((x) => (
                <option key={x.id} value={x.id}>
                  {x.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        <label className="inline-flex items-center gap-2 text-sm">
          <input
            type="checkbox"
            checked={!!form.active}
            onChange={(e) => setForm((prev) => ({ ...prev, active: e.target.checked }))}
            className="h-4 w-4"
          />
          Activo
        </label>

        <div className="border rounded px-3 py-3 bg-slate-50">
          <h4 className="font-semibold mb-2">Branding</h4>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <label className="block text-sm">
              Color primario
              <input
                type="color"
                value={branding.color_primario}
                onChange={(e) => updateBranding({ color_primario: e.target.value })}
                className="mt-2 h-10 w-20 border border-slate-300 rounded"
              />
            </label>
            <label className="block text-sm">
              Color secundario
              <input
                type="color"
                value={branding.color_secundario || '#111827'}
                onChange={(e) => updateBranding({ color_secundario: e.target.value })}
                className="mt-2 h-10 w-20 border border-slate-300 rounded"
              />
            </label>
            <label className="block text-sm">
              Dashboard template
              <select
                value={branding.dashboard_template}
                onChange={(e) => updateBranding({ dashboard_template: e.target.value })}
                className="mt-1 border px-2 py-1 w-full rounded"
              >
                {TEMPLATE_OPTIONS.map((opt) => (
                  <option key={opt} value={opt}>
                    {opt}
                  </option>
                ))}
              </select>
            </label>
          </div>
        </div>

        <div className="border rounded px-3 py-3 bg-white">
          <h4 className="font-semibold mb-2">Feature Flags</h4>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
            {featureOptions.map((option) => (
              <label key={option.key} className="flex items-center gap-2 text-sm text-gray-900">
                <input
                  type="checkbox"
                  checked={Boolean(form.template_config.features?.[option.key])}
                  onChange={(e) => toggleFeature(option.key, e.target.checked)}
                  className="h-4 w-4 rounded border-gray-300"
                />
                {option.label}
              </label>
            ))}
          </div>
          <p className="text-xs text-slate-500 mt-2">
            Estos flags controlan qué componentes o campos mostraremos en los tenants que usen esta plantilla.
          </p>
        </div>

        <div>
          <label className="block mb-1">Config JSON (opcional)</label>
          <textarea
            value={rawConfig}
            onChange={(e) => {
              const value = e.target.value
              setRawConfig(value)
              try {
                const parsed = JSON.parse(value || '{}')
                setForm((prev) => ({ ...prev, template_config: ensureTemplateConfig(parsed) }))
              } catch {
                // ignorar hasta que sea válido
              }
            }}
            rows={8}
            className="w-full border px-3 py-2 font-mono rounded"
          />
          <p className="text-xs text-slate-500 mt-1">
            Puedes editar la configuración avanzada; debe ser un JSON válido.
          </p>
        </div>

        <div className="pt-2">
          <button type="submit" className="bg-blue-600 text-white px-3 py-2 rounded">
            Guardar
          </button>
          <button type="button" className="ml-3 px-3 py-2" onClick={() => nav('..')}>
            Cancelar
          </button>
        </div>
      </form>
    </div>
  )
}

import React, { useCallback, useEffect, useState } from 'react'

import { Link, useNavigate } from 'react-router-dom'

import {
  listSectores,
  removeSector,
  type Sector,
} from '../../../services/configuracion/sectores'
import { listTipoEmpresa, type TipoEmpresa } from '../../../services/configuracion/tipo-empresa'
import { listTipoNegocio, type TipoNegocio } from '../../../services/configuracion/tipo-negocio'
import { useToast, getErrorMessage } from '../../../shared/toast'

export default function SectorList() {
  const [items, setItems] = useState<Sector[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [empresas, setEmpresas] = useState<Record<string, string>>({})
  const [negocios, setNegocios] = useState<Record<string, string>>({})
  const nav = useNavigate()
  const { success, error: toastError } = useToast()

  useEffect(() => {
    (async () => {
      try {
        setLoading(true)
        const [sectoresData, empresasData, negociosData] = await Promise.all([
          listSectores(),
          listTipoEmpresa(),
          listTipoNegocio(),
        ])
        setItems(sectoresData)
        setEmpresas(Object.fromEntries((empresasData as TipoEmpresa[]).map((e) => [e.id, e.name])))
        setNegocios(Object.fromEntries((negociosData as TipoNegocio[]).map((n) => [n.id, n.name])))
        setError(null)
      } catch (e: any) {
        const m = getErrorMessage(e)
        setError(m)
        toastError(m)
      } finally {
        setLoading(false)
      }
    })()
  }, [])

  const getEmpresaNombre = useCallback(
    (id?: string | null) => (id && empresas[id] ? empresas[id] : '—'),
    [empresas]
  )
  const getNegocioNombre = useCallback(
    (id?: string | null) => (id && negocios[id] ? negocios[id] : '—'),
    [negocios]
  )

  return (
    <div style={{ padding: 16 }}>
      <div className="flex justify-between items-center mb-3">
        <h3 className="text-xl font-semibold">Sectores</h3>
        <button className="bg-blue-600 text-white px-3 py-1 rounded" onClick={() => nav('nuevo')}>
          Nuevo
        </button>
      </div>
      {loading && <div className="text-sm text-gray-500">Cargando…</div>}
      {error && <div className="bg-red-100 text-red-700 px-3 py-2 rounded mb-3">{error}</div>}
      <table className="min-w-full bg-white border border-gray-200 rounded">
        <thead className="bg-gray-50">
          <tr>
            <th className="text-left py-2 px-3">Nombre</th>
            <th className="text-left py-2 px-3">Código</th>
            <th className="text-left py-2 px-3">Descripción</th>
            <th className="text-left py-2 px-3">Tipo Empresa</th>
            <th className="text-left py-2 px-3">Tipo Negocio</th>
            <th className="text-left py-2 px-3">Activo</th>
            <th className="text-left py-2 px-3">Branding</th>
            <th className="text-left py-2 px-3">Acciones</th>
          </tr>
        </thead>
        <tbody>
          {items.map((it) => {
            const color = it.template_config?.branding?.color_primario
            return (
              <tr key={it.id} className="border-t">
                <td className="py-2 px-3">{it.name}</td>
                <td className="py-2 px-3">{it.code || '—'}</td>
                <td className="py-2 px-3">{it.description || '—'}</td>
                <td className="py-2 px-3">
                  {getEmpresaNombre(it.template_config?.defaults?.business_type_id as string)}
                </td>
                <td className="py-2 px-3">
                  {getNegocioNombre(it.template_config?.defaults?.business_category_id as string)}
                </td>
                <td className="py-2 px-3">{it.active ? 'Sí' : 'No'}</td>
                <td className="py-2 px-3">
                  {color ? (
                    <span className="inline-flex items-center gap-2">
                      <span
                        style={{
                          width: 18,
                          height: 18,
                          borderRadius: 4,
                          display: 'inline-block',
                          backgroundColor: color,
                          border: '1px solid #cbd5e1',
                        }}
                      />
                      <span>{color}</span>
                    </span>
                  ) : (
                    <span className="text-gray-400 text-sm">Sin definir</span>
                  )}
                </td>
                <td className="py-2 px-3">
                  <Link to={`${it.id}/editar`} className="text-blue-600 hover:underline mr-3">
                    Editar
                  </Link>
                  <button
                    className="text-red-700"
                    onClick={async () => {
                      if (!confirm('¿Eliminar sector?')) return
                      try {
                        await removeSector(it.id)
                        setItems((prev) => prev.filter((x) => x.id !== it.id))
                        success('Sector eliminado')
                      } catch (e: any) {
                        toastError(getErrorMessage(e))
                      }
                    }}
                  >
                    Eliminar
                  </button>
                </td>
              </tr>
            )
          })}
          {!loading && items.length === 0 && (
            <tr>
              <td className="py-3 px-3" colSpan={7}>
                Sin sectores
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import {
  listSystemDefaults,
  updateSystemDefault,
  type SystemDefault,
} from '../../../services/configuracion/system-defaults'
import { getErrorMessage, useToast } from '../../../shared/toast'

const CATEGORY_LABELS: Record<string, string> = {
  app: 'App',
  company: 'Empresa',
  reports: 'Reportes',
  invoicing: 'Facturación',
  tax: 'Impuestos',
  theme: 'Tema',
  general: 'General',
  modules: 'Módulos',
  numbering: 'Numeración',
  pos: 'Punto de venta',
  sector: 'Sector',
}

function isJsonValue(val: string): boolean {
  const v = val.trim()
  return v.startsWith('{') || v.startsWith('[')
}

function splitKey(key: string): { ns: string; name: string } {
  const dot = key.indexOf('.')
  if (dot === -1) return { ns: '', name: key }
  return { ns: key.slice(0, dot), name: key.slice(dot + 1) }
}

function Spinner() {
  return (
    <span className="inline-block h-3.5 w-3.5 border-2 border-current border-t-transparent rounded-full animate-spin" />
  )
}

export default function SystemDefaultsForm() {
  const [items, setItems] = useState<SystemDefault[]>([])
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState<string | null>(null)
  const [savingAll, setSavingAll] = useState(false)
  const [edited, setEdited] = useState<Record<string, string>>({})
  const [original, setOriginal] = useState<Record<string, string>>({})
  const [activeCategory, setActiveCategory] = useState<string | null>(null)
  const { success, error: toastError } = useToast()

  useEffect(() => {
    setLoading(true)
    listSystemDefaults()
      .then((rows) => {
        setItems(rows)
        const init: Record<string, string> = {}
        rows.forEach((row) => { init[row.key] = row.value_text ?? '' })
        setEdited(init)
        setOriginal(init)
        const firstCat = rows[0]?.category ?? null
        setActiveCategory(firstCat)
      })
      .catch((e) => toastError(getErrorMessage(e)))
      .finally(() => setLoading(false))
  }, [])

  const isDirty = (key: string) => edited[key] !== original[key]

  const categories = Array.from(new Set(items.map((i) => i.category)))

  const dirtyInCategory = (cat: string) =>
    items.filter((i) => i.category === cat && isDirty(i.key)).length

  const allDirtyKeys = items.filter((i) => isDirty(i.key)).map((i) => i.key)

  const handleSave = async (key: string) => {
    setSaving(key)
    try {
      const updated = await updateSystemDefault(key, edited[key] ?? '')
      setItems((prev) =>
        prev.map((item) =>
          item.key === key
            ? { ...item, value_text: updated.value_text, updated_at: updated.updated_at }
            : item
        )
      )
      setOriginal((prev) => ({ ...prev, [key]: edited[key] ?? '' }))
      success(`"${key}" actualizado`)
    } catch (e: any) {
      toastError(getErrorMessage(e))
    } finally {
      setSaving(null)
    }
  }

  const handleSaveAll = async () => {
    setSavingAll(true)
    let saved = 0
    let failed = 0
    for (const key of allDirtyKeys) {
      try {
        const updated = await updateSystemDefault(key, edited[key] ?? '')
        setItems((prev) =>
          prev.map((item) =>
            item.key === key
              ? { ...item, value_text: updated.value_text, updated_at: updated.updated_at }
              : item
          )
        )
        setOriginal((prev) => ({ ...prev, [key]: edited[key] ?? '' }))
        saved++
      } catch {
        failed++
      }
    }
    setSavingAll(false)
    if (saved > 0) success(`${saved} valor${saved !== 1 ? 'es' : ''} guardado${saved !== 1 ? 's' : ''}`)
    if (failed > 0) toastError(`${failed} no se pudo${failed !== 1 ? 'n' : ''} guardar`)
  }

  const set = (key: string, value: string) =>
    setEdited((prev) => ({ ...prev, [key]: value }))

  const renderEditor = (item: SystemDefault) => {
    const value = edited[item.key] ?? ''

    if (item.value_type === 'boolean') {
      const checked = value.toLowerCase() === 'true'
      return (
        <div className="flex items-center gap-3">
          <button
            type="button"
            role="switch"
            aria-checked={checked}
            onClick={() => set(item.key, checked ? 'false' : 'true')}
            className={`relative inline-flex h-6 w-11 flex-shrink-0 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-1 ${
              checked ? 'bg-blue-600' : 'bg-gray-200'
            }`}
          >
            <span
              className={`inline-block h-4 w-4 transform rounded-full bg-white shadow transition-transform ${
                checked ? 'translate-x-6' : 'translate-x-1'
              }`}
            />
          </button>
          <span className="text-sm text-gray-600">{checked ? 'Activado' : 'Desactivado'}</span>
        </div>
      )
    }

    if (item.value_type === 'color') {
      return (
        <div className="flex items-center gap-3">
          <label className="cursor-pointer" title="Abrir selector de color">
            <div
              className="h-9 w-9 rounded-lg border-2 border-white shadow ring-1 ring-gray-200 flex-shrink-0 transition-transform hover:scale-110"
              style={{ backgroundColor: value || '#ffffff' }}
            />
            <input
              type="color"
              value={value || '#ffffff'}
              onChange={(e) => set(item.key, e.target.value)}
              className="sr-only"
            />
          </label>
          <input
            type="text"
            value={value}
            onChange={(e) => set(item.key, e.target.value)}
            className="border border-gray-200 px-2.5 py-1.5 rounded-md text-sm font-mono w-28 focus:outline-none focus:ring-2 focus:ring-blue-400 bg-gray-50"
            placeholder="#000000"
          />
        </div>
      )
    }

    if (isJsonValue(value) || item.value_type === 'json') {
      return (
        <textarea
          value={value}
          onChange={(e) => set(item.key, e.target.value)}
          rows={Math.min(10, Math.max(3, value.split('\n').length + 1))}
          spellCheck={false}
          className="w-full border border-gray-200 px-3 py-2 rounded-md text-xs font-mono focus:outline-none focus:ring-2 focus:ring-blue-400 bg-gray-50 resize-y"
        />
      )
    }

    return (
      <input
        type={item.value_type === 'number' ? 'number' : 'text'}
        step={item.value_type === 'number' ? 'any' : undefined}
        value={value}
        onChange={(e) => set(item.key, e.target.value)}
        className="w-full border border-gray-200 px-2.5 py-1.5 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 bg-gray-50"
      />
    )
  }

  const activeItems = items.filter((i) => i.category === activeCategory)

  // Special grid layout for theme colors
  const isColorGroup = activeCategory === 'theme' && activeItems.every(
    (i) => i.value_type === 'color' || i.value_type === 'text'
  )
  const colorItems = activeItems.filter((i) => i.value_type === 'color')
  const nonColorItems = activeItems.filter((i) => i.value_type !== 'color')

  if (loading) {
    return (
      <div className="flex h-96 gap-6 p-4">
        <div className="w-44 flex-shrink-0 space-y-2">
          {[1, 2, 3, 4, 5, 6].map((i) => (
            <div key={i} className="h-8 rounded-lg bg-gray-100 animate-pulse" />
          ))}
        </div>
        <div className="flex-1 space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="rounded-xl border border-gray-100 bg-white p-4 space-y-2">
              <div className="h-4 w-48 rounded bg-gray-200 animate-pulse" />
              <div className="h-3 w-72 rounded bg-gray-100 animate-pulse" />
              <div className="h-8 w-full rounded bg-gray-100 animate-pulse mt-3" />
            </div>
          ))}
        </div>
      </div>
    )
  }

  if (items.length === 0) {
    return (
      <div className="p-6">
        <div className="rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800">
          No hay defaults configurados. Reinicia el servidor para generar la tabla inicial.
        </div>
      </div>
    )
  }

  return (
    <div className="flex flex-col h-full" style={{ padding: 16 }}>
      {/* Header */}
      <div className="flex items-start justify-between mb-5">
        <div>
          <h3 className="text-lg font-semibold text-gray-900">Defaults del sistema</h3>
          <p className="text-sm text-gray-500 mt-0.5">
            Valores globales aplicados a todos los tenants salvo configuración propia.
          </p>
        </div>
        {allDirtyKeys.length > 0 && (
          <button
            onClick={handleSaveAll}
            disabled={savingAll}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium disabled:opacity-60 hover:bg-blue-700 transition-colors flex-shrink-0 ml-4 shadow-sm"
          >
            {savingAll ? <><Spinner /> Guardando…</> : `Guardar ${allDirtyKeys.length} cambio${allDirtyKeys.length !== 1 ? 's' : ''}`}
          </button>
        )}
      </div>

      {/* Body: sidebar + content */}
      <div className="flex gap-5 flex-1 min-h-0">
        {/* Sidebar */}
        <nav className="w-44 flex-shrink-0 space-y-0.5">
          {categories.map((cat) => {
            const dirty = dirtyInCategory(cat)
            const active = cat === activeCategory
            return (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`w-full flex items-center justify-between px-3 py-2 rounded-lg text-sm text-left transition-colors ${
                  active
                    ? 'bg-blue-50 text-blue-700 font-medium'
                    : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                }`}
              >
                <span>{CATEGORY_LABELS[cat] ?? cat}</span>
                {dirty > 0 && (
                  <span className={`text-xs rounded-full px-1.5 py-0.5 font-medium ${
                    active ? 'bg-blue-100 text-blue-700' : 'bg-amber-100 text-amber-700'
                  }`}>
                    {dirty}
                  </span>
                )}
              </button>
            )
          })}
        </nav>

        {/* Content */}
        <div className="flex-1 min-w-0 overflow-y-auto space-y-3">
          {/* Color swatches grid for theme colors */}
          {colorItems.length > 0 && (
            <div>
              <p className="text-xs font-medium text-gray-400 uppercase tracking-wide mb-2">Colores</p>
              <div className="grid grid-cols-3 gap-3">
                {colorItems.map((item) => {
                  const value = edited[item.key] ?? ''
                  const dirty = isDirty(item.key)
                  const { name } = splitKey(item.key)
                  return (
                    <div
                      key={item.key}
                      className={`rounded-xl border p-3 bg-white transition-colors ${
                        dirty ? 'border-amber-300 ring-1 ring-amber-200' : 'border-gray-200'
                      }`}
                    >
                      <label className="cursor-pointer block mb-2" title="Cambiar color">
                        <div
                          className="h-12 rounded-lg border border-black/10 transition-transform hover:scale-105"
                          style={{ backgroundColor: value || '#ffffff' }}
                        />
                        <input
                          type="color"
                          value={value || '#ffffff'}
                          onChange={(e) => set(item.key, e.target.value)}
                          className="sr-only"
                        />
                      </label>
                      <div className="text-xs font-medium text-gray-700 truncate" title={item.key}>{name}</div>
                      <div className="flex items-center gap-1.5 mt-1.5">
                        <input
                          type="text"
                          value={value}
                          onChange={(e) => set(item.key, e.target.value)}
                          className="flex-1 min-w-0 border border-gray-200 px-1.5 py-1 rounded text-xs font-mono bg-gray-50 focus:outline-none focus:ring-1 focus:ring-blue-400"
                          placeholder="#000000"
                        />
                        <button
                          onClick={() => handleSave(item.key)}
                          disabled={saving === item.key || !dirty}
                          className={`flex-shrink-0 px-2 py-1 rounded text-xs font-medium transition-colors ${
                            dirty
                              ? 'bg-blue-600 text-white hover:bg-blue-700'
                              : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                          }`}
                        >
                          {saving === item.key ? <Spinner /> : '✓'}
                        </button>
                      </div>
                    </div>
                  )
                })}
              </div>
            </div>
          )}

          {/* Non-color settings (or all settings if not theme) */}
          {nonColorItems.length > 0 && (
            <div>
              {colorItems.length > 0 && (
                <p className="text-xs font-medium text-gray-400 uppercase tracking-wide mb-2 mt-4">Otros</p>
              )}
              <div className="space-y-2">
                {nonColorItems.map((item) => {
                  const dirty = isDirty(item.key)
                  const { ns, name } = splitKey(item.key)
                  const isLong = isJsonValue(edited[item.key] ?? '') || item.value_type === 'json'
                  return (
                    <div
                      key={item.key}
                      className={`rounded-xl border bg-white p-4 transition-colors ${
                        dirty ? 'border-amber-300 ring-1 ring-amber-200' : 'border-gray-200'
                      }`}
                    >
                      <div className="flex items-start justify-between gap-3 mb-3">
                        <div className="min-w-0">
                          <div className="flex items-center gap-1.5 flex-wrap">
                            {ns && (
                              <span className="text-xs text-gray-400 font-mono">{ns}.</span>
                            )}
                            <span className="text-sm font-semibold text-gray-800 font-mono">{name}</span>
                            {dirty && (
                              <span className="inline-flex items-center gap-1 text-xs bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded-full font-medium">
                                Sin guardar
                              </span>
                            )}
                          </div>
                          {item.description && (
                            <p className="text-xs text-gray-400 mt-0.5 leading-relaxed">{item.description}</p>
                          )}
                        </div>
                        {!isLong && (
                          <button
                            onClick={() => handleSave(item.key)}
                            disabled={saving === item.key || !dirty}
                            className={`flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                              dirty
                                ? 'bg-blue-600 text-white hover:bg-blue-700'
                                : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                            }`}
                          >
                            {saving === item.key ? <Spinner /> : 'Guardar'}
                          </button>
                        )}
                      </div>

                      {renderEditor(item)}

                      {isLong && (
                        <div className="flex justify-end mt-2">
                          <button
                            onClick={() => handleSave(item.key)}
                            disabled={saving === item.key || !dirty}
                            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                              dirty
                                ? 'bg-blue-600 text-white hover:bg-blue-700'
                                : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                            }`}
                          >
                            {saving === item.key ? <><Spinner /> Guardando…</> : 'Guardar'}
                          </button>
                        </div>
                      )}
                    </div>
                  )
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import { useNavigate, useParams } from 'react-router-dom'

import { createTimezone, getTimezone, updateTimezone, type Timezone } from '../../../services/configuracion/timezones'

export default function TimezoneForm() {
  const { id } = useParams()
  const nav = useNavigate()
  const isEdit = !!id
  const [form, setForm] = useState<Timezone>({ name: '', display_name: '', offset_minutes: 0, active: true })
  const [loading, setLoading] = useState(false)
  const [msg, setMsg] = useState<string | null>(null)

  useEffect(() => {
    if (!isEdit) return
    ;(async () => {
      try { setLoading(true); const data = await getTimezone(id as string); setForm(data) } catch (e: any) { setMsg(e?.message || 'Error') } finally { setLoading(false) }
    })()
  }, [id])

  async function save() {
    setMsg(null); setLoading(true)
    try {
      const payload = { ...form, name: String(form.name||'').trim() }
      if (!payload.name) throw new Error('Nombre requerido')
      if (isEdit) await updateTimezone(id as string, payload as any)
      else await createTimezone(payload as any)
      nav('..')
    } catch (e: any) { setMsg(e?.message || 'Error') } finally { setLoading(false) }
  }

  return (
    <div className="admin-form">
      <h2 style={{ marginTop: 0 }}>{isEdit ? 'Editar Timezone' : 'Nuevo Timezone'}</h2>
      {msg && <div className="notice">{msg}</div>}
      <div className="grid" style={{ gap: 12, maxWidth: 520 }}>
        <label>Nombre (ID)
          <input className="input" value={form.name} onChange={(e)=> setForm(prev=> ({...prev, name: e.target.value}))} disabled={isEdit} />
        </label>
        <label>Mostrar como
          <input className="input" value={form.display_name} onChange={(e)=> setForm(prev=> ({...prev, display_name: e.target.value}))} />
        </label>
        <label>Offset (minutos)
          <input className="input" type="number" value={form.offset_minutes ?? 0} onChange={(e)=> setForm(prev=> ({...prev, offset_minutes: Number(e.target.value)}))} />
        </label>
        <label style={{ display: 'inline-flex', alignItems: 'center', gap: 8 }}>
          <input type="checkbox" checked={form.active !== false} onChange={(e)=> setForm(prev=> ({...prev, active: e.target.checked}))} /> Activo
        </label>
      </div>
      <div style={{ marginTop: 12 }}>
        <button className="gc-button gc-button--primary" onClick={save} disabled={loading}>Guardar</button>
        <button className="gc-button" onClick={()=> nav('..')} disabled={loading} style={{ marginLeft: 8 }}>Cancelar</button>
      </div>
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import { Link } from 'react-router-dom'

import { listTimezones, removeTimezone, type Timezone } from '../../../services/configuracion/timezones'

export default function TimezoneList() {
  const [items, setItems] = useState<Timezone[]>([])
  const [loading, setLoading] = useState(false)
  const [msg, setMsg] = useState<string | null>(null)

  async function load() {
    setLoading(true)
    try { setItems(await listTimezones()) } catch (e: any) { setMsg(e?.message || 'Error') } finally { setLoading(false) }
  }
  useEffect(() => { load() }, [])

  async function del(name: string) {
    if (!confirm('¿Eliminar timezone?')) return
    await removeTimezone(name)
    setItems(prev => prev.filter(x => x.name !== name))
  }

  return (
    <div className="admin-list">
      <div className="admin-list__header">
        <h2>Timezones</h2>
        <Link to="nuevo" className="gc-button gc-button--primary">Nuevo</Link>
      </div>
      {msg && <div className="notice">{msg}</div>}
      {loading ? 'Cargando…' : (
        <table className="min-w-full text-sm">
          <thead><tr><th>Nombre</th><th>Mostrar</th><th>Offset</th><th>Activo</th><th></th></tr></thead>
          <tbody>
            {items.length === 0 && <tr><td colSpan={5}>Sin timezones</td></tr>}
            {items.map((it) => (
              <tr key={it.name}>
                <td>{it.name}</td>
                <td>{it.display_name}</td>
                <td>{it.offset_minutes ?? ''}</td>
                <td>{it.active !== false ? 'Sí' : 'No'}</td>
                <td style={{ textAlign: 'right' }}>
                  <Link to={`${encodeURIComponent(it.name)}/editar`} className="gc-button">Editar</Link>
                  <button className="gc-button" onClick={() => del(it.name)}>Eliminar</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import { useNavigate, useParams } from 'react-router-dom'

import { createTipoEmpresa, getTipoEmpresa, updateTipoEmpresa, type TipoEmpresa as T } from '../../../services/configuracion/tipo-empresa'
import { useToast, getErrorMessage } from '../../../shared/toast'

type FormT = Omit<T, 'id'>

export default function TipoEmpresaForm() {
  const { id } = useParams()
  const nav = useNavigate()
  const [form, setForm] = useState<FormT>({ name: '', description: '', active: true })
  const { success, error } = useToast()

  useEffect(() => {
    if (id) {
      getTipoEmpresa(id)
        .then((x) => setForm({ name: x.name, description: x.description ?? '', active: x.active ?? true }))
        .catch(() => {})
    }
  }, [id])

  const onSubmit: React.FormEventHandler = async (e) => {
    e.preventDefault()
    try {
      if (!form.name?.trim()) throw new Error('Name is required')
      const payload: FormT = { ...form, name: form.name.trim() }
      if (id) await updateTipoEmpresa(id, payload)
      else await createTipoEmpresa(payload)
      success('Tipo de empresa guardado')
      nav('..')
    } catch(e:any) {
      error(getErrorMessage(e))
    }
  }

  return (
    <div style={{ padding: 16 }}>
      <h3 className="text-xl font-semibold mb-3">{id ? 'Editar tipo de empresa' : 'Nuevo tipo de empresa'}</h3>
      <form onSubmit={onSubmit} className="space-y-4" style={{ maxWidth: 520 }}>
        <div>
          <label className="block mb-1">Nombre</label>
          <input value={form.name} onChange={(e)=> setForm({ ...form, name: e.target.value })} className="border px-2 py-1 w-full rounded" required />
        </div>
        <div className="pt-2">
          <button type="submit" className="bg-blue-600 text-white px-3 py-2 rounded">Guardar</button>
          <button type="button" className="ml-3 px-3 py-2" onClick={()=> nav('..')}>Cancelar</button>
        </div>
      </form>
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import { Link, useNavigate } from 'react-router-dom'

import { listTipoEmpresa, removeTipoEmpresa, type TipoEmpresa } from '../../../services/configuracion/tipo-empresa'
import { useToast, getErrorMessage } from '../../../shared/toast'

export default function TipoEmpresaList() {
  const [items, setItems] = useState<TipoEmpresa[]>([])
  const [loading, setLoading] = useState(false)
  const [errMsg, setErrMsg] = useState<string | null>(null)
  const nav = useNavigate()
  const { success, error: toastError } = useToast()

  useEffect(() => {
    ;(async () => {
      try {
        setLoading(true)
        setItems(await listTipoEmpresa())
      } catch (e: any) {
        const m = getErrorMessage(e)
        setErrMsg(m)
        toastError(m)
      } finally {
        setLoading(false)
      }
    })()
  }, [])

  return (
    <div style={{ padding: 16 }}>
      <div className="flex justify-between items-center mb-3">
        <h3 className="text-xl font-semibold">Tipo de empresa</h3>
        <button className="bg-blue-600 text-white px-3 py-1 rounded" onClick={() => nav('nuevo')}>Nuevo</button>
      </div>
      {loading && <div className="text-sm text-gray-500">Cargando…</div>}
      {errMsg && <div className="bg-red-100 text-red-700 px-3 py-2 rounded mb-3">{errMsg}</div>}
      <table className="min-w-full bg-white border border-gray-200 rounded">
        <thead className="bg-gray-50">
          <tr>
            <th className="text-left py-2 px-3">Nombre</th>
            <th className="text-left py-2 px-3">Acciones</th>
          </tr>
        </thead>
        <tbody>
          {items.map((it) => (
            <tr key={it.id} className="border-t">
              <td className="py-2 px-3">{it.name}</td>
              <td className="py-2 px-3">
                <Link to={`${it.id}/editar`} className="text-blue-600 hover:underline mr-3">Editar</Link>
                <button
                  className="text-red-700"
                  onClick={async () => {
                    if (!confirm('¿Eliminar?')) return
                    try {
                      await removeTipoEmpresa(it.id)
                      setItems((p) => p.filter((x) => x.id !== it.id))
                      success('Tipo de empresa eliminada')
                    } catch (e: any) {
                      toastError(getErrorMessage(e))
                    }
                  }}
                >
                  Eliminar
                </button>
              </td>
            </tr>
          ))}
          {!loading && items.length === 0 && (
            <tr>
              <td className="py-3 px-3" colSpan={2}>
                Sin registros
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  )
}

