export default function ModuloForm({ mode }: { mode: 'create' | 'edit' }) {
  const navigate = useNavigate()
  const { id } = useParams()
  const [form, setForm] = useState<Partial<Module>>({
    name: '',
    initial_template: '',
    category: null,
    description: null,
    icon: null,
    url: null,
    active: true,
  })
  const [saving, setSaving] = useState(false)
  const { success, error } = useToast()

  useEffect(() => {
    if (mode === 'edit' && id) {
      getModulo(id)
        .then((m) =>
          setForm({
            ...m,
            initial_template: m.initial_template || '',
            description: m.description ?? '',
          }),
        )
        .catch((e: any) => {
          const status = e?.response?.status
          if (status === 404) {
            error('El módulo ya no existe; regresando al listado')
            navigate('..')
          } else {
            error(getErrorMessage(e))
          }
        })
    }
  }, [mode, id])

  const set = (field: string, value: string | null) =>
    setForm((f) => ({ ...f, [field]: value }))

  const onSubmit: React.FormEventHandler = async (e) => {
    e.preventDefault()
    try {
      setSaving(true)
      if (!form.name?.trim() || !form.initial_template?.trim())
        throw new Error('Complete name and initial template')
      if (mode === 'edit' && id) {
        await updateModulo(id, form)
      } else {
        await createModulo(form)
      }
      success('Módulo guardado')
      navigate('..')
    } catch (e: any) {
      error(getErrorMessage(e))
    } finally {
      setSaving(false)
    }
  }

  const isEdit = mode === 'edit'

  return (
    <div style={s.page}>
      {/* Back */}
      <button style={s.backLink} onClick={() => navigate('..')}>
        ← Volver a módulos
      </button>

      <form onSubmit={onSubmit}>
        <div style={s.card}>
          {/* Card header */}
          <div style={s.cardHeader}>
            <div style={s.headerIcon}>{form.icon || '🧩'}</div>
            <div>
              <h2 style={s.headerTitle}>{isEdit ? 'Editar módulo' : 'Crear módulo'}</h2>
              <p style={s.headerSub}>
                {isEdit ? `Editando: ${form.name || ''}` : 'Nuevo módulo del sistema'}
              </p>
            </div>
          </div>

          {/* Form body */}
          <div style={s.body}>
            {/* Name + URL */}
            <div style={s.row}>
              <div style={s.field}>
                <label style={s.label}>Nombre *</label>
                <input
                  style={s.input}
                  name="name"
                  value={form.name || ''}
                  onChange={(e) => set('name', e.target.value)}
                  placeholder="products"
                  required
                />
              </div>
              <div style={s.field}>
                <label style={s.label}>URL</label>
                <input
                  style={s.input}
                  name="url"
                  value={form.url || ''}
                  onChange={(e) => set('url', e.target.value || null)}
                  placeholder="products"
                />
              </div>
            </div>

            {/* Template + Icon */}
            <div style={s.row}>
              <div style={s.field}>
                <label style={s.label}>Initial template *</label>
                <input
                  style={s.input}
                  name="initial_template"
                  value={form.initial_template || ''}
                  onChange={(e) => set('initial_template', e.target.value)}
                  placeholder="products"
                  required
                />
              </div>
              <div style={s.field}>
                <label style={s.label}>Icono</label>
                <input
                  style={s.input}
                  name="icon"
                  value={form.icon || ''}
                  onChange={(e) => set('icon', e.target.value || null)}
                  placeholder="📦"
                />
              </div>
            </div>

            {/* Category */}
            <div style={s.field}>
              <label style={s.label}>Categoría</label>
              <select
                style={s.select}
                value={form.category || ''}
                onChange={(e) => set('category', e.target.value || null)}
              >
                {CATEGORIES.map((c) => (
                  <option key={c.value} value={c.value}>{c.label}</option>
                ))}
              </select>
            </div>

            {/* Description */}
            <div style={s.field}>
              <label style={s.label}>Descripción</label>
              <textarea
                style={s.textarea}
                value={form.description || ''}
                onChange={(e) => set('description', e.target.value || null)}
                placeholder="Breve descripción del módulo"
                rows={2}
              />
            </div>
          </div>

          {/* Footer actions */}
          <div style={s.footer}>
            <button type="button" style={s.btnCancel} onClick={() => navigate('..')}>
              Cancelar
            </button>
            <button type="submit" style={s.btnSave} disabled={saving}>
              {saving ? 'Guardando…' : 'Guardar'}
            </button>
          </div>
        </div>
      </form>
    </div>
  )
}

/**
 * Notification Center Component
 * Displays notifications list with filtering and actions
 */

import React, { useState } from 'react';

import { useNotifications } from '../../hooks/useNotifications';
import './styles.css';

export const NotificationCenter: React.FC = () => {
  const {
    notifications,
    unreadCount,
    loading,
    error,
    markAsRead,
    markAllAsRead,
  } = useNotifications(true, 10000);

  const [filter, setFilter] = useState<'all' | 'unread'>('all');

  const filteredNotifications =
    filter === 'unread'
      ? notifications.filter((n) => !n.read)
      : notifications;

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'success':
        return (
          <svg className="notification-item__icon notification-item__icon--success" viewBox="0 0 24 24" fill="currentColor">
            <path d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" />
          </svg>
        );
      case 'warning':
        return (
          <svg className="notification-item__icon notification-item__icon--warning" viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
          </svg>
        );
      case 'error':
        return (
          <svg className="notification-item__icon notification-item__icon--error" viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
          </svg>
        );
      default:
        return (
          <svg className="notification-item__icon notification-item__icon--info" viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
          </svg>
        );
    }
  };

  return (
    <div className="notification-center">
      <div className="notification-center__header">
        <h2 className="notification-center__title">Notificaciones</h2>
        <div className="notification-center__actions">
          {unreadCount > 0 && (
            <button
              className="notification-center__mark-all-btn"
              onClick={() => markAllAsRead()}
              title="Marcar todas como leídas"
            >
              Marcar todas como leídas
            </button>
          )}
        </div>
      </div>

      {error && (
        <div className="notification-center__error">
          Error al cargar notificaciones: {error.message}
        </div>
      )}

      <div className="notification-center__filters">
        <button
          className={`notification-center__filter ${filter === 'all' ? 'is-active' : ''}`}
          onClick={() => setFilter('all')}
        >
          Todas ({notifications.length})
        </button>
        <button
          className={`notification-center__filter ${filter === 'unread' ? 'is-active' : ''}`}
          onClick={() => setFilter('unread')}
        >
          Sin leer ({unreadCount})
        </button>
      </div>

      <div className="notification-center__list">
        {loading ? (
          <div className="notification-center__loading">
            <p>Cargando notificaciones...</p>
          </div>
        ) : filteredNotifications.length === 0 ? (
          <div className="notification-center__empty">
            <p>{filter === 'unread' ? 'No hay notificaciones sin leer' : 'No hay notificaciones'}</p>
          </div>
        ) : (
          filteredNotifications.map((notification) => (
            <div
              key={notification.id}
              className={`notification-item ${!notification.read ? 'is-unread' : ''}`}
              onClick={() => !notification.read && markAsRead(notification.id)}
            >
              <div className="notification-item__icon-wrapper">
                {getNotificationIcon(notification.type)}
              </div>
              <div className="notification-item__content">
                <h3 className="notification-item__title">{notification.title}</h3>
                <p className="notification-item__message">{notification.message}</p>
                {notification.related_entity && (
                  <p className="notification-item__entity">
                    {notification.related_entity.name}
                  </p>
                )}
                <span className="notification-item__time">
                  {new Date(notification.created_at).toLocaleDateString('es-ES', {
                    year: 'numeric',
                    month: 'short',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </span>
              </div>
              {!notification.read && (
                <div className="notification-item__unread-indicator"></div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

/**
 * Webhook Form Modal
 * For creating and editing webhooks with event selection
 */

import React, { useState, useEffect } from 'react';

import { createWebhook, updateWebhook, Webhook } from '../../services/webhooks';
import './webhook-form.css';

interface WebhookFormProps {
  webhook?: Webhook;
  onClose: () => void;
  onSuccess?: () => void;
}

const AVAILABLE_EVENTS = [
  // Invoice events
  { group: 'Invoices', events: [
    'invoice.created',
    'invoice.sent',
    'invoice.authorized',
    'invoice.rejected',
    'invoice.cancelled',
  ]},
  // Payment events
  { group: 'Payments', events: [
    'payment.received',
    'payment.failed',
  ]},
  // Customer events
  { group: 'Customers', events: [
    'customer.created',
    'customer.updated',
  ]},
  // Sales Order events
  { group: 'Sales Orders', events: [
    'sales_order.created',
    'sales_order.confirmed',
    'sales_order.cancelled',
  ]},
  // Inventory events
  { group: 'Inventory', events: [
    'inventory.updated',
    'inventory.low',
  ]},
];

export const WebhookForm: React.FC<WebhookFormProps> = ({
  webhook,
  onClose,
  onSuccess,
}) => {
  const [formData, setFormData] = useState({
    url: webhook?.url || '',
    events: webhook?.events || [],
    secret: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [validationErrors, setValidationErrors] = useState<Record<string, string>>({});

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {};

    if (!formData.url.trim()) {
      errors.url = 'URL is required';
    } else if (!formData.url.startsWith('https://')) {
      errors.url = 'URL must start with https://';
    } else if (formData.url.length > 2048) {
      errors.url = 'URL is too long (max 2048 characters)';
    }

    if (formData.events.length === 0) {
      errors.events = 'Select at least one event';
    }

    if (formData.secret) {
      if (formData.secret.length < 8) {
        errors.secret = 'Secret must be at least 8 characters';
      } else if (formData.secret.length > 500) {
        errors.secret = 'Secret is too long (max 500 characters)';
      }
    }

    setValidationErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleEventToggle = (event: string) => {
    setFormData((prev) => ({
      ...prev,
      events: prev.events.includes(event)
        ? prev.events.filter((e) => e !== event)
        : [...prev.events, event],
    }));
  };

  const handleSelectAllGroup = (events: string[]) => {
    setFormData((prev) => {
      const allSelected = events.every((e) => prev.events.includes(e));
      const newEvents = allSelected
        ? prev.events.filter((e) => !events.includes(e))
        : [...new Set([...prev.events, ...events])];
      return { ...prev, events: newEvents };
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!validateForm()) {
      return;
    }

    try {
      setLoading(true);
      const payload = {
        url: formData.url.trim(),
        events: formData.events,
        ...(formData.secret && { secret: formData.secret }),
      };

      if (webhook) {
        await updateWebhook(webhook.id, payload);
      } else {
        await createWebhook(payload);
      }

      onSuccess?.();
      onClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error saving webhook');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="webhook-form-modal">
      <div className="webhook-form-modal__overlay" onClick={onClose} />
      <form className="webhook-form-modal__form" onSubmit={handleSubmit}>
        <div className="webhook-form-modal__header">
          <h2>{webhook ? 'Edit Webhook' : 'Create Webhook'}</h2>
          <button
            type="button"
            className="webhook-form-modal__close"
            onClick={onClose}
            aria-label="Close modal"
          >
            ×
          </button>
        </div>

        <div className="webhook-form-modal__body">
          {error && (
            <div className="webhook-form-modal__alert webhook-form-modal__alert--error">
              {error}
            </div>
          )}

          {/* URL Field */}
          <div className="webhook-form-modal__field">
            <label htmlFor="url">
              Webhook URL <span className="webhook-form-modal__required">*</span>
            </label>
            <input
              id="url"
              type="url"
              placeholder="https://your-app.com/webhooks"
              value={formData.url}
              onChange={(e) => {
                setFormData((prev) => ({ ...prev, url: e.target.value }));
                if (validationErrors.url) {
                  setValidationErrors((prev) => ({ ...prev, url: '' }));
                }
              }}
              className={validationErrors.url ? 'is-invalid' : ''}
              disabled={loading}
            />
            {validationErrors.url && (
              <div className="webhook-form-modal__field-error">
                {validationErrors.url}
              </div>
            )}
            <small>Must use HTTPS protocol</small>
          </div>

          {/* Secret Field */}
          <div className="webhook-form-modal__field">
            <label htmlFor="secret">Secret (Optional)</label>
            <input
              id="secret"
              type="password"
              placeholder="Enter webhook secret"
              value={formData.secret}
              onChange={(e) => {
                setFormData((prev) => ({ ...prev, secret: e.target.value }));
                if (validationErrors.secret) {
                  setValidationErrors((prev) => ({ ...prev, secret: '' }));
                }
              }}
              className={validationErrors.secret ? 'is-invalid' : ''}
              disabled={loading}
            />
            {validationErrors.secret && (
              <div className="webhook-form-modal__field-error">
                {validationErrors.secret}
              </div>
            )}
            <small>Used to sign webhook payloads (HMAC-SHA256)</small>
          </div>

          {/* Events Field */}
          <div className="webhook-form-modal__field">
            <label>
              Events <span className="webhook-form-modal__required">*</span>
            </label>
            <div className="webhook-form-modal__events">
              {AVAILABLE_EVENTS.map(({ group, events }) => (
                <div key={group} className="webhook-form-modal__event-group">
                  <div className="webhook-form-modal__event-group-header">
                    <label className="webhook-form-modal__event-group-label">
                      <input
                        type="checkbox"
                        checked={events.every((e) => formData.events.includes(e))}
                        onChange={() => handleSelectAllGroup(events)}
                        disabled={loading}
                      />
                      <strong>{group}</strong>
                    </label>
                  </div>
                  <div className="webhook-form-modal__event-list">
                    {events.map((event) => (
                      <label
                        key={event}
                        className="webhook-form-modal__event-checkbox"
                      >
                        <input
                          type="checkbox"
                          checked={formData.events.includes(event)}
                          onChange={() => handleEventToggle(event)}
                          disabled={loading}
                        />
                        <code className="webhook-form-modal__event-name">
                          {event}
                        </code>
                      </label>
                    ))}
                  </div>
                </div>
              ))}
            </div>
            {validationErrors.events && (
              <div className="webhook-form-modal__field-error">
                {validationErrors.events}
              </div>
            )}
          </div>

          {/* Info Section */}
          <div className="webhook-form-modal__info">
            <h4>About Webhooks</h4>
            <ul>
              <li>Webhooks are HTTP POST requests sent to your URL when events occur</li>
              <li>Each request includes a signature header for verification</li>
              <li>
                Failed deliveries are retried automatically with exponential backoff
              </li>
              <li>You can view delivery logs and retry failed deliveries manually</li>
            </ul>
          </div>
        </div>

        <div className="webhook-form-modal__footer">
          <button
            type="button"
            className="webhook-form-modal__cancel"
            onClick={onClose}
            disabled={loading}
          >
            Cancel
          </button>
          <button
            type="submit"
            className="webhook-form-modal__submit"
            disabled={loading}
          >
            {loading ? 'Saving...' : 'Save Webhook'}
          </button>
        </div>
      </form>
    </div>
  );
};

/**
 * Webhook Logs Component
 * Displays execution logs for a specific webhook
 */

import React, { useState, useEffect } from 'react';

import { getWebhookLogs, WebhookLog } from '../../services/webhooks';
import './styles.css';

interface WebhookLogsProps {
  webhookId: string;
}

export const WebhookLogs: React.FC<WebhookLogsProps> = ({ webhookId }) => {
  const [logs, setLogs] = useState<WebhookLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  useEffect(() => {
    const fetchLogs = async () => {
      try {
        setLoading(true);
        const response = await getWebhookLogs(webhookId, { limit: 20 });
        setLogs(response.logs);
        setError(null);
      } catch (err) {
        setError(err instanceof Error ? err : new Error('Error loading logs'));
        console.error('Logs error:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchLogs();
  }, [webhookId]);

  return (
    <div className="webhook-logs">
      <h3 className="webhook-logs__title">Logs de Ejecución</h3>

      {error && (
        <div className="webhook-logs__error">{error.message}</div>
      )}

      {loading ? (
        <div className="webhook-logs__loading">Cargando logs...</div>
      ) : logs.length === 0 ? (
        <div className="webhook-logs__empty">No hay logs disponibles</div>
      ) : (
        <div className="webhook-logs__list">
          {logs.map((log) => (
            <div
              key={log.id}
              className={`webhook-log-item ${log.success ? 'is-success' : 'is-failed'}`}
              onClick={() => setExpandedId(expandedId === log.id ? null : log.id)}
            >
              <div className="webhook-log-item__header">
                <div className="webhook-log-item__status">
                  {log.success ? '✓' : '✗'}
                </div>
                <div className="webhook-log-item__info">
                  <span className="webhook-log-item__event">{log.event}</span>
                  <span className="webhook-log-item__code">{log.response_status}</span>
                </div>
                <span className="webhook-log-item__time">
                  {new Date(log.created_at).toLocaleString('es-ES')}
                </span>
              </div>
              {expandedId === log.id && (
                <div className="webhook-log-item__details">
                  <div className="webhook-log-item__section">
                    <h4 className="webhook-log-item__section-title">Payload</h4>
                    <pre className="webhook-log-item__code-block">
                      {JSON.stringify(log.payload, null, 2)}
                    </pre>
                  </div>
                  {log.response_body && (
                    <div className="webhook-log-item__section">
                      <h4 className="webhook-log-item__section-title">Respuesta</h4>
                      <pre className="webhook-log-item__code-block">
                        {log.response_body}
                      </pre>
                    </div>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

/**
 * Webhooks List Component
 * Displays list of webhooks with actions
 */

import React, { useState, useEffect } from 'react';

import { getWebhooks, testWebhook, deleteWebhook, Webhook } from '../../services/webhooks';
import './styles.css';

interface WebhooksListProps {
  onEdit?: (webhook: Webhook) => void;
  onRefresh?: () => void;
}

export const WebhooksList: React.FC<WebhooksListProps> = ({ onEdit, onRefresh }) => {
  const [webhooks, setWebhooks] = useState<Webhook[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);
  const [testingId, setTestingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const fetchWebhooks = async () => {
    try {
      setLoading(true);
      const response = await getWebhooks({ limit: 50 });
      setWebhooks(response.webhooks);
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err : new Error('Error loading webhooks'));
      console.error('Webhooks error:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWebhooks();
  }, []);

  const handleTest = async (webhook: Webhook) => {
    try {
      setTestingId(webhook.id);
      const result = await testWebhook(webhook.id);
      alert(`Test result: ${result.success ? 'Success' : 'Failed'} (Status: ${result.status})`);
    } catch (err) {
      alert(`Test failed: ${err instanceof Error ? err.message : 'Unknown error'}`);
    } finally {
      setTestingId(null);
    }
  };

  const handleDelete = async (webhookId: string) => {
    if (!confirm('¿Estás seguro de que deseas eliminar este webhook?')) return;

    try {
      setDeletingId(webhookId);
      await deleteWebhook(webhookId);
      setWebhooks((prev) => prev.filter((w) => w.id !== webhookId));
      onRefresh?.();
    } catch (err) {
      alert(`Delete failed: ${err instanceof Error ? err.message : 'Unknown error'}`);
    } finally {
      setDeletingId(null);
    }
  };

  return (
    <div className="webhooks-list">
      {error && (
        <div className="webhooks-list__error">
          {error.message}
          <button onClick={fetchWebhooks}>Reintentar</button>
        </div>
      )}

      {loading ? (
        <div className="webhooks-list__loading">Cargando webhooks...</div>
      ) : webhooks.length === 0 ? (
        <div className="webhooks-list__empty">No hay webhooks configurados</div>
      ) : (
