                const matchingSector = sectores.find(
                    (s) =>
                        s.code === data.sector_template_name ||
                        s.name === data.sector_template_name ||
                        s.id === data.sector_template_name
                );

                if (matchingSector) {
                    setSelectedSector(matchingSector.id);
