import React, { useEffect, useMemo, useState } from 'react'

import { Link, useParams } from 'react-router-dom'

import { Container } from './Container'
import { getEmpresa } from '../services/empresa'
import { listEmpresaModulos, listModulosPublicos, removeEmpresaModulo, upsertEmpresaModulo } from '../services/modulos'
import { getErrorMessage, useToast } from '../shared/toast'

import type { CompanyModule, Module } from '../modulos/types'

function fmtDate(value?: string | null) {
  if (!value) return '—'
  const d = new Date(value)
  if (Number.isNaN(d.getTime())) return value
  return d.toLocaleDateString()
}

function classNames(...parts: Array<string | false | null | undefined>) {
  return parts.filter(Boolean).join(' ')
}

export function EmpresaModulos() {
  const { id } = useParams()
  const empresaId = id as string
  const { success, error } = useToast()

  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [empresa, setEmpresa] = useState<any>(null)

  const [catalogo, setCatalogo] = useState<Module[]>([])
  const [asignados, setAsignados] = useState<CompanyModule[]>([])

  const [search, setSearch] = useState('')
  const [active, setActive] = useState(true)
  const [expirationDate, setExpirationDate] = useState<string>('')
  const [initialTemplate, setInitialTemplate] = useState<string>('')
  const [lastPicked, setLastPicked] = useState<Module | null>(null)

  const assignedIds = useMemo(() => new Set(asignados.map((a) => String(a.module_id))), [asignados])

  const candidatos = useMemo(() => {
    const q = search.trim().toLowerCase()
    return catalogo
      .filter((m) => !assignedIds.has(String(m.id)))
      .filter((m) => {
        if (!q) return true
        const hay = `${m.name ?? ''} ${m.category ?? ''} ${m.description ?? ''}`.toLowerCase()
        return hay.includes(q)
      })
      .sort((a, b) => {
        const ca = (a.category ?? '').toLowerCase()
        const cb = (b.category ?? '').toLowerCase()
        if (ca !== cb) return ca.localeCompare(cb)
        return (a.name ?? '').localeCompare(b.name ?? '')
      })
  }, [catalogo, assignedIds, search])

  useEffect(() => {
    ;(async () => {
      try {
        setLoading(true)
        const [empresaData, mods, empMods] = await Promise.all([
          getEmpresa(empresaId),
          listModulosPublicos(),
          listEmpresaModulos(empresaId),
        ])
        const moduloLookup = new Map(mods.map((m) => [String(m.id), m]))
        const enrichedAsignados = empMods.map((registro: any) => {
          if (registro.module?.name) return registro
          const moduloInfo = moduloLookup.get(String(registro.module_id))
          return moduloInfo ? { ...registro, module: moduloInfo } : registro
        })
        setEmpresa(empresaData)
        setCatalogo(mods)
        setAsignados(enrichedAsignados)
      } catch (e: any) {
        error(getErrorMessage(e))
      } finally {
        setLoading(false)
      }
    })()
  }, [empresaId])

  const onAgregar = async (modulo: Module) => {
    try {
      setSaving(true)
      setLastPicked(modulo)
      const moduloId = String(modulo.id)
      await upsertEmpresaModulo(empresaId, moduloId, {
        active,
        expiration_date: expirationDate || null,
        initial_template: initialTemplate || modulo.initial_template || null,
      })

      setAsignados((prev) => {
        const exists = prev.some((x) => String(x.module_id) === String(moduloId))
        const newRow: CompanyModule = {
          id: String(Date.now()),
          tenant_id: empresaId,
          active,
          module_id: String(moduloId),
          expiration_date: expirationDate || null,
          initial_template: initialTemplate || modulo.initial_template || null,
          module: modulo ?? null,
        }
        return exists ? prev.map((x) => (String(x.module_id) === String(moduloId) ? newRow : x)) : [...prev, newRow]
      })

      setSearch('')
      setActive(true)
      setExpirationDate('')
      setInitialTemplate('')
      success('Module assigned')
    } catch (e: any) {
      error(getErrorMessage(e))
    } finally {
      setSaving(false)
    }
  }

  const onToggleActive = async (moduloId: string, nextActive: boolean) => {
    try {
      setSaving(true)
      const current = asignados.find((x) => String(x.module_id) === String(moduloId))
      await upsertEmpresaModulo(empresaId, moduloId, {
        active: nextActive,
        expiration_date: current?.expiration_date ?? null,
        initial_template: current?.initial_template ?? null,
      })
      setAsignados((prev) => prev.map((x) => (String(x.module_id) === String(moduloId) ? { ...x, active: nextActive } : x)))
      success(nextActive ? 'Module activated' : 'Module deactivated')
    } catch (e: any) {
      error(getErrorMessage(e))
    } finally {
      setSaving(false)
    }
  }

  const onEliminar = async (moduloId: number | string) => {
    if (!confirm('Remove module from company?')) return
    try {
      setSaving(true)
      await removeEmpresaModulo(empresaId, moduloId)
      setAsignados((prev) => prev.filter((x) => String(x.module_id) !== String(moduloId)))
      success('Module removed')
    } catch (e: any) {
      error(getErrorMessage(e))
    } finally {
      setSaving(false)
    }
  }

  const companyName = empresa?.nombre || empresa?.name || empresa?.slug || empresaId

  return (
    <Container className="empresa-page">
      <header className="empresa-header">
        <div className="modules-header-row">
          <div>
            <h1 className="empresa-title">Company modules</h1>
            <p className="empresa-subtitle">
              Assign, configure and revoke modules for <span className="badge">{companyName}</span>
            </p>
          </div>
          <Link to="/admin/companies" className="action-pill blue">
            Back
          </Link>
        </div>
      </header>

      {loading ? (
        <div className="empresa-muted">Loading…</div>
      ) : (
        <div className="modules-layout">
          <div className="card">
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, flexWrap: 'wrap' }}>
              <div>
                <div className="text-base font-semibold">Assign settings</div>
                <div className="muted text-sm">Click a module card to assign it.</div>
              </div>
              <span className="badge">{candidatos.length} available</span>
            </div>

            <div className="module-settings">
              <div>
                <label className="block text-sm font-medium mb-1">Search</label>
                <input
                  className="input"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder="Search by name, category…"
                />
              </div>

              <div className="module-setting-row">
                <label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 13, fontWeight: 700 }}>
                  <input type="checkbox" checked={active} onChange={(e) => setActive(e.target.checked)} />
                  Active
                </label>
                <span className={classNames('badge', active ? '' : 'badge-warning')}>{active ? 'Enabled' : 'Disabled'}</span>
              </div>

              <div className="module-form-grid">
                <div>
                  <label className="block text-sm font-medium mb-1">Expiration date</label>
                  <input type="date" className="input" value={expirationDate} onChange={(e) => setExpirationDate(e.target.value)} />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-1">Initial template</label>
                  <input
                    className="input"
                    value={initialTemplate}
                    onChange={(e) => setInitialTemplate(e.target.value)}
                    placeholder={lastPicked?.initial_template || 'Defaults to module template'}
                  />
                </div>
              </div>

              {lastPicked && (
                <div className="text-sm">
                  <div className="muted">Last assigned</div>
                  <div className="flex items-center gap-2">
                    <span>{lastPicked.icon || ''}</span>
                    <span className="font-semibold">{lastPicked.name}</span>
                    {lastPicked.category ? <span className="badge">{lastPicked.category}</span> : null}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="card">
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, flexWrap: 'wrap' }}>
              <div>
                <div className="text-base font-semibold">Assigned modules</div>
                <div className="muted text-sm">Modules currently available for this company.</div>
              </div>
              <span className="badge">{asignados.length} assigned</span>
            </div>

            <div className="mt-4">
              <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between', gap: 12, flexWrap: 'wrap' }}>
                <div style={{ fontSize: 13, fontWeight: 800 }}>Available modules</div>
                <div className="muted" style={{ fontSize: 12 }}>Click to assign</div>
              </div>
              <div className="module-cards">
                {candidatos.map((m) => (
                  <button
                    key={m.id}
                    type="button"
                    disabled={saving}
                    onClick={() => onAgregar(m)}
                    className="module-card"
                    title="Click to assign"
                  >
                    <div className="module-card__top">
                      <div style={{ minWidth: 0 }}>
                        <div className="module-card__title">
                          <span className="module-card__icon">{(m.icon || '').trim()}</span>
                          <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{m.name}</span>
                        </div>
                        <div className="module-card__meta">
                          {m.category ? <span className="badge">{m.category}</span> : <span className="badge">General</span>}
                          <span className="module-card__cta">Assign</span>
                        </div>
                      </div>
                    </div>
                    {m.description ? <div className="module-card__desc">{m.description}</div> : null}
                  </button>
                ))}
                {candidatos.length === 0 && (
                  <div className="empresa-muted">
                    No modules available to assign.
                  </div>
                )}
              </div>
            </div>

            <div className="mt-4 table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Module</th>
                    <th>Status</th>
                    <th>Activated</th>
                    <th>Expires</th>
                    <th style={{ textAlign: 'right' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {asignados.map((a) => {
                    const name = a.module?.name || a.module_id
                    const icon = a.module?.icon || ''
                    return (
                      <tr key={a.module_id}>
                        <td>
                          <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                            <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                              <span>{icon}</span>
                              <span style={{ fontWeight: 700 }}>{name}</span>
                              {a.module?.category ? <span className="badge">{a.module.category}</span> : null}
                            </div>
                            <div className="muted id">{String(a.module_id)}</div>
                          </div>
                        </td>
                        <td>
                          <span className={classNames('badge', !a.active && 'badge-warning')}>{a.active ? 'Active' : 'Inactive'}</span>
                        </td>
                        <td className="muted">{fmtDate(a.activation_date)}</td>
                        <td className="muted">{fmtDate(a.expiration_date)}</td>
                        <td style={{ textAlign: 'right' }}>
                          <div className="action-pills">
                            <button className={classNames('action-pill', a.active ? 'violet' : 'green')} disabled={saving} onClick={() => onToggleActive(String(a.module_id), !a.active)}>
                              {a.active ? 'Deactivate' : 'Activate'}
                            </button>
                            <button className="action-pill danger" disabled={saving} onClick={() => onEliminar(a.module_id)}>
                              Remove
                            </button>
                          </div>
                        </td>
                      </tr>
                    )
                  })}
                  {asignados.length === 0 && (
                    <tr>
                      <td colSpan={5} className="empresa-muted">
                        No modules assigned yet.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Container>
  )
}

// src/pages/admin/empresas/EmpresaPanel.tsx <img src="/icons/empresas.png" alt="Empresas" className="w-7 h-7" />
import React, { useState } from 'react';

import { Link } from "react-router-dom";

import { Container } from './Container';
import { DeleteAllCompaniesModal } from '../components/DeleteAllCompaniesModal';
import { DeleteEmpresaModal } from '../components/DeleteCompanyModal';
import { useEmpresas } from '../hooks/useEmpresas';
import { deleteAllEmpresas, deleteEmpresa, purgeOrphanCompanyData } from '../services/empresa';

export const EmpresaPanel: React.FC = () => {
  const { empresas, loading, error } = useEmpresas();
  const [search, setSearch] = useState('');
  const [empresaAEliminar, setEmpresaAEliminar] = useState<{ id: string; name: string } | null>(null);
  const [deletedIds, setDeletedIds] = useState<Set<string>>(new Set());
  const [showDeleteAllModal, setShowDeleteAllModal] = useState(false);
  const [purgingOrphans, setPurgingOrphans] = useState(false);

  const normalizedSearch = search.trim().toLowerCase();
  const empresasDisponibles = (empresas ?? []).filter((e) => !deletedIds.has(String(e?.id)));
  const empresasFiltradas = (empresas ?? []).filter((e) => {
    const nombre = (e?.nombre || e?.name || '').toString().toLowerCase();
    return nombre.includes(normalizedSearch) && !deletedIds.has(String(e?.id));
  });

  const handleConfirmDelete = async (tenantId: string) => {
    const safeTenantId = (tenantId || '').trim();
    if (!safeTenantId) {
      throw new Error('Invalid company id');
    }
    const res: any = await deleteEmpresa(safeTenantId);
    setDeletedIds((prev) => {
      const next = new Set(prev);
      next.add(String(safeTenantId));
      return next;
    });
    return {
      ok: true,
      tenant_id: safeTenantId,
      name: empresaAEliminar?.name || '',
      registros_eliminados: res?.registros_eliminados || {
        usuarios: 0,
        productos: 0,
        facturas: 0,
        clientes: 0,
        modulos: 0,
        roles: 0,
      },
    };
  };

  const handleDeleteAll = async () => {
    try {
      const res: any = await deleteAllEmpresas();
      const deleted = Array.isArray(res?.deleted) ? res.deleted : [];
      setDeletedIds((prev) => {
        const next = new Set(prev);
        deleted.forEach((item: any) => {
          const tid = item?.tenant_id ? String(item.tenant_id) : '';
          if (tid) next.add(tid);
        });
        return next;
      });
      return {
        ok: Boolean(res?.ok),
        total: Number(res?.total || 0),
        deleted_count: Number(res?.deleted_count || 0),
        failed_count: Number(res?.failed_count || 0),
        failed: Array.isArray(res?.failed) ? res.failed : [],
      };
    } catch (e: any) {
      const status = e?.response?.status;
      if (status !== 404) throw e;

      // Fallback for older backends where /bulk/delete-all is not deployed yet.
      const targets = empresasDisponibles.map((empresa: any) => ({
        id: String(empresa?.id ?? empresa?.tenant_id ?? '').trim(),
        name: String(empresa?.nombre ?? empresa?.name ?? ''),
      })).filter((x) => x.id);

      const deleted: string[] = [];
      const failed: Array<{ tenant_id: string; name?: string; detail?: string }> = [];

      for (const target of targets) {
        try {
          await deleteEmpresa(target.id);
          deleted.push(target.id);
        } catch (err: any) {
          failed.push({
            tenant_id: target.id,
            name: target.name,
            detail: err?.response?.data?.detail || err?.message || 'Unknown error',
          });
        }
      }

      setDeletedIds((prev) => {
        const next = new Set(prev);
        deleted.forEach((id) => next.add(id));
        return next;
      });

      return {
        ok: failed.length === 0,
        total: targets.length,
        deleted_count: deleted.length,
        failed_count: failed.length,
        failed,
      };
    }
  };

  const handlePurgeOrphans = async () => {
    const ok = window.confirm(
      'This will remove orphan rows from related tables (users/modules/roles without tenant). Continue?'
    );
    if (!ok) return;
    try {
      setPurgingOrphans(true);
      const res: any = await purgeOrphanCompanyData();
      const deleted = res?.deleted || {};
      const lines = Object.keys(deleted)
        .sort()
        .map((k) => `${k}: ${Number(deleted[k] || 0)}`);
      window.alert(`Orphan cleanup completed.\n\n${lines.join('\n')}`);
    } catch (e: any) {
      window.alert(e?.response?.data?.detail || e?.message || 'Error purging orphan data');
    } finally {
      setPurgingOrphans(false);
    }
  };

  return (
    <Container className="empresa-page">
      <header className="empresa-header">
        <h1 className="empresa-title">Company management</h1>
        <p className="empresa-subtitle">Manage companies, modules, and access from one place.</p>
      </header>

      <div className="empresa-toolbar">
        <input
          type="search"
          placeholder="Search company..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="empresa-search"
        />
        <Link to="create" className="empresa-primary">
          New company
        </Link>
        <button
          type="button"
          onClick={() => setShowDeleteAllModal(true)}
          disabled={!empresasDisponibles.length}
          className="action-pill danger"
          title="Delete all companies"
        >
          Delete all
        </button>
        <button
          type="button"
          onClick={handlePurgeOrphans}
          disabled={purgingOrphans}
          className="action-pill amber"
          title="Purge orphan rows"
        >
          {purgingOrphans ? 'Purging...' : 'Purge orphans'}
        </button>
      </div>

      {loading ? (
        <p className="empresa-muted">Loading...</p>
      ) : error ? (
        <p className="empresa-muted" style={{ color: '#dc2626' }}>Error loading companies</p>
      ) : empresasFiltradas.length > 0 ? (
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Company</th>
                <th>Modules</th>
                <th style={{ textAlign: 'right' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {empresasFiltradas.map((empresa) => {
                const empresaId = String((empresa as any)?.id ?? (empresa as any)?.tenant_id ?? '').trim();
                const nombreEmpresa = empresa?.nombre || (empresa as any)?.name || 'Sin nombre';
                const modulos = (empresa as any)?.modulos || (empresa as any)?.modules || [];
                return (
                  <tr key={empresaId || String(empresa.id)}>
                    <td style={{ fontWeight: 600 }}>{nombreEmpresa}</td>
                    <td>
                      {modulos.length > 0 ? (
                        <div className="badge-group">
                          {modulos.map((modulo: string) => (
                            <span key={`${empresaId}-${modulo}`} className="badge">
                              {modulo}
                            </span>
                          ))}
                        </div>
                      ) : (
                        <span className="badge badge-warning">No modules</span>
                      )}
                    </td>
                    <td style={{ textAlign: 'right' }}>
                      <div className="action-pills">
                        <Link to={`/admin/companies/${empresaId}/edit`} className="action-pill blue">
                          Edit
                        </Link>
                        <Link to={`/admin/companies/${empresaId}/users`} className="action-pill green">
                          Users
                        </Link>
                        <Link to={`/admin/companies/modules/${empresaId}`} className="action-pill amber">
                          Modules
                        </Link>
                        <Link to={`/admin/companies/${empresaId}/config`} className="action-pill violet">
                          Config
                        </Link>
                        <button
                          onClick={() => setEmpresaAEliminar({ id: empresaId, name: nombreEmpresa })}
                          className="action-pill danger"
                          disabled={!empresaId}
                        >
                          Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="empresa-empty">No companies registered.</div>
      )}

      {empresaAEliminar && (
        <DeleteEmpresaModal
          empresa={empresaAEliminar}
          onClose={() => setEmpresaAEliminar(null)}
          onConfirm={handleConfirmDelete}
        />
      )}

      {showDeleteAllModal && (
        <DeleteAllCompaniesModal
          companyCount={empresasDisponibles.length}
          onClose={() => setShowDeleteAllModal(false)}
          onConfirm={handleDeleteAll}
        />
      )}
    </Container>
  );
};

// src/pages/CompanyUsuarios.tsx

import React, { useCallback, useEffect, useState } from 'react'

import { useParams, Link } from 'react-router-dom'

import { Container } from './Container'
import {
  listCompanyUsers,
  createCompanyUser,
  updateCompanyUser,
  resetUserPassword,
  toggleUserActive,
  deleteUser,
  getUserActivity,
  CompanyUser,
  CreateUserPayload,
  UpdateUserPayload,
  UserActivity,
} from '../services/company-users'
import { getEmpresa } from '../services/empresa'
import { useToast } from '../shared/toast'

const ROLES_DISPONIBLES = [
  { value: 'owner', label: 'Owner (Full Admin)' },
  { value: 'manager', label: 'Manager (Management)' },
  { value: 'cajero', label: 'Cashier/Operator (POS)' },
  { value: 'contable', label: 'Accountant (Billing)' },
  { value: 'vendedor', label: 'Salesperson (Sales)' },
  { value: 'almacen', label: 'Warehouse (Stock)' },
]

export const CompanyUsuarios: React.FC = () => {
  const { id } = useParams<{ id: string }>()
  const { show: showToast } = useToast()

  const [empresa, setEmpresa] = useState<any>(null)
  const [usuarios, setUsuarios] = useState<CompanyUser[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [filtroActivo, setFiltroActivo] = useState<'all' | 'activo' | 'inactivo'>('all')

  // Modals
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showEditModal, setShowEditModal] = useState(false)
  const [showActivityModal, setShowActivityModal] = useState(false)
  const [selectedUser, setSelectedUser] = useState<CompanyUser | null>(null)
  const [userActivity, setUserActivity] = useState<UserActivity[]>([])

  // Form state
  const [formData, setFormData] = useState<CreateUserPayload>({
    email: '',
    name: '',
    apellidos: '',
    password: '',
    roles: [],
  })

  const [editFormData, setEditFormData] = useState<UpdateUserPayload>({
    name: '',
    apellidos: '',
    roles: [],
    active: true,
  })

  const loadData = useCallback(async () => {
    if (!id) return
    setLoading(true)
    try {
      const [empresaData, usersData] = await Promise.all([
        getEmpresa(id),
        listCompanyUsers(id),
      ])
      setEmpresa(empresaData)
      setUsuarios(usersData.users || usersData || [])
    } catch (err: any) {
      showToast('Error loading data', 'error')
      console.error(err)
    } finally {
      setLoading(false)
    }
  }, [id, showToast])

  // Cargar empresa y usuarios
  useEffect(() => {
    void loadData()
  }, [loadData])

  // Filtrado
  const usuariosFiltrados = usuarios.filter((u) => {
    const matchSearch =
      u.email.toLowerCase().includes(search.toLowerCase()) ||
      u.name.toLowerCase().includes(search.toLowerCase())
    const matchActivo =
      filtroActivo === 'all' ||
      (filtroActivo === 'activo' && u.active) ||
      (filtroActivo === 'inactivo' && !u.active)
    return matchSearch && matchActivo
  })

  // Crear usuario
  const handleCreateUser = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!id) return

    // Validaciones
    if (!formData.email || !formData.name || !formData.password) {
      showToast('Email, name and password are required', 'error')
      return
    }
    if (formData.roles.length === 0) {
      showToast('You must assign at least one role', 'error')
      return
    }

    try {
      await createCompanyUser(id, formData)
      showToast('User created successfully. Credentials sent via email.', 'success')
      setShowCreateModal(false)
      resetFormData()
      await loadData()
    } catch (err: any) {
      showToast(err.response?.data?.detail || 'Error creating user', 'error')
      console.error(err)
    }
  }

  // Actualizar usuario
  const handleUpdateUser = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!id || !selectedUser) return

    if (!editFormData.roles || editFormData.roles.length === 0) {
      showToast('You must assign at least one role', 'error')
      return
    }

    try {
      await updateCompanyUser(id, selectedUser.id, editFormData)
      showToast('User updated successfully', 'success')
      setShowEditModal(false)
      setSelectedUser(null)
      await loadData()
    } catch (err: any) {
      showToast(err.response?.data?.detail || 'Error updating user', 'error')
      console.error(err)
    }
  }

  // Resetear password
  const handleResetPassword = async (user: CompanyUser) => {
    if (!id) return
    if (!confirm(`Reset password for ${user.email}? A new password will be sent via email.`)) {
      return
    }

    try {
      await resetUserPassword(id, user.id)
      showToast('Password reset. New password sent via email.', 'success')
    } catch (err: any) {
      showToast(err.response?.data?.detail || 'Error resetting password', 'error')
      console.error(err)
    }
  }

  // Toggle activo
  const handleToggleActive = async (user: CompanyUser) => {
    if (!id) return
    const action = user.active ? 'deactivate' : 'activate'
    if (!confirm(`Confirm ${action} user ${user.email}?`)) {
      return
    }

    try {
      await toggleUserActive(id, user.id, !user.active)
      showToast(`User ${action}d successfully`, 'success')
      await loadData()
    } catch (err: any) {
      showToast(err.response?.data?.detail || `Error ${action} user`, 'error')
