      {!lastCreatedCompany && success && <div className="cc-alert success">{success}</div>}

      <form onSubmit={onSubmit}>
        <div className="cc-layout">
          <div className="cc-stack">
            <section className="cc-panel">
              <div className="cc-panel-head">
