/**
 * Dashboard Page
 * Main admin dashboard with KPIs and analytics
 */

import React, { useState } from 'react';

import { useTranslation } from 'react-i18next';

import { DashboardStats } from '../features/dashboard/DashboardStats';
import { KpiBoard } from '../features/dashboard/KpiBoard';
import { useDashboard } from '../hooks/useDashboard';
import '../features/dashboard/styles.css';
import '../features/dashboard/dashboard-page.css';

export const Dashboard: React.FC = () => {
  const { stats, kpis, loading, error, refetch } = useDashboard(true, 30000);
  const { t } = useTranslation();
  const [refreshing, setRefreshing] = useState(false);

  const handleRefresh = async () => {
    setRefreshing(true);
    try {
      await refetch();
    } finally {
      setRefreshing(false);
    }
  };

  return (
    <div className="dashboard-page">
      <div className="dashboard-page__header">
        <div>
          <h1 className="dashboard-page__title">Dashboard</h1>
          <p className="dashboard-page__subtitle">
            {t('dashboard.subtitle')}
          </p>
        </div>
        <button
          className={`dashboard-page__refresh-btn ${refreshing ? 'is-loading' : ''}`}
          onClick={handleRefresh}
          disabled={refreshing || loading}
          title={t('dashboard.refreshTitle')}
        >
          <svg className="dashboard-page__refresh-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
          </svg>
          {t('dashboard.refresh')}
        </button>
      </div>

      {error && (
        <div className="dashboard-page__error">
          <p>{t('dashboard.loadError', { message: error.message })}</p>
          <button onClick={handleRefresh} className="dashboard-page__error-retry">
            {t('dashboard.retry')}
          </button>
        </div>
      )}

      <DashboardStats data={kpis} loading={loading} />
      <KpiBoard data={kpis} loading={loading} />

      {stats && (
        <div className="dashboard-page__recent">
          <h2 className="dashboard-page__section-title">{t('dashboard.recentCompanies')}</h2>
          <div className="dashboard-page__companies-grid">
            {stats.ultimos_tenants && stats.ultimos_tenants.length > 0 ? (
              stats.ultimos_tenants.map((tenant) => (
                <div key={tenant.id} className="dashboard-page__company-card">
                  <h3 className="dashboard-page__company-name">{tenant.name}</h3>
                  <p className="dashboard-page__company-date">
                    {new Date(tenant.created_at).toLocaleDateString('es-ES', {
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                    })}
                  </p>
                </div>
              ))
            ) : (
              <p className="dashboard-page__empty">{t('dashboard.noCompanies')}</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react'

import { useNavigate, useParams, Link } from 'react-router-dom'

import { getEmpresa, updateEmpresa } from '../services/empresa'
import { useToast, getErrorMessage } from '../shared/toast'

export function EditarEmpresa() {
  const { id } = useParams()
  const navigate = useNavigate()
  const { success, error } = useToast()
  const [loading, setLoading] = useState(true)
  const [form, setForm] = useState<{ nombre: string; slug?: string }>({ nombre: '' })

  useEffect(() => {
    (async () => {
      try {
        setLoading(true)
        const data = await getEmpresa(id as string)
        setForm({ nombre: data?.nombre ?? data?.name ?? '', slug: data?.slug || '' })
      } catch (e: any) {
        error(getErrorMessage(e))
      } finally {
        setLoading(false)
      }
    })()
  }, [id])

  const onChange: React.ChangeEventHandler<HTMLInputElement> = (e) =>
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }))

  const onSubmit: React.FormEventHandler = async (e) => {
    e.preventDefault()
    try {
      await updateEmpresa(id as string, form)
      success('Company updated')
      navigate('/admin/companies')
    } catch (e: any) {
      error(getErrorMessage(e))
    }
  }

  return (
    <div className="p-4">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-semibold">Edit Company</h2>
        <Link to="/admin/companies" className="text-sm text-blue-600">Back</Link>
      </div>
      {loading ? (
        <div className="text-sm text-gray-500">Loading…</div>
      ) : (
        <form onSubmit={onSubmit} className="space-y-4 max-w-md">
          <div>
            <label className="block mb-1">Name</label>
            <input name="nombre" value={form.nombre} onChange={onChange} className="border px-2 py-1 w-full rounded" required />
          </div>
          <div>
            <label className="block mb-1">Slug</label>
            <input name="slug" value={form.slug || ''} onChange={onChange} className="border px-2 py-1 w-full rounded" />
          </div>
          <div className="pt-2">
            <button type="submit" className="bg-blue-600 text-white px-3 py-2 rounded">Save</button>
          </div>
        </form>
      )}
    </div>
  )
}

/**
 * IncidenciasPanel.tsx
 * Gestión de incidencias con IA auto-resolución
 * Tabs: Activas, Resueltas, Stock Alerts
 */

import React, { useState, useEffect } from 'react'

import IncidentDetailModal from '../components/IncidentDetailModal'
import { useAuth } from '../auth/AuthContext'
import { useAuthGuard } from '../hooks/useAuthGuard'
import {
  listIncidents,
  analyzeIncident,
  autoResolveIncident,
  assignIncident,
  closeIncident,
  listStockAlerts,
  notifyStockAlert,
  resolveStockAlert
} from '../services/incidents'

import type { Incident, StockAlert } from '../types/incidents'

type Tab = 'activas' | 'resueltas' | 'stock_alerts'

export default function IncidenciasPanel() {
  useAuthGuard('superadmin')
  const { profile } = useAuth()

  const [activeTab, setActiveTab] = useState<Tab>('activas')
  const [incidents, setIncidents] = useState<Incident[]>([])
  const [stockAlerts, setStockAlerts] = useState<StockAlert[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedIncident, setSelectedIncident] = useState<Incident | null>(null)

  useEffect(() => {
    loadData()
  }, [activeTab])

  const upsertIncident = (updated: Incident) => {
    setIncidents((prev) =>
      prev.some((item) => item.id === updated.id)
        ? prev.map((item) => (item.id === updated.id ? updated : item))
        : [updated, ...prev]
    )
    setSelectedIncident((prev) => (prev?.id === updated.id ? updated : prev))
  }

  const loadData = async () => {
    setLoading(true)
    try {
      if (activeTab === 'stock_alerts') {
        const data = await listStockAlerts({ estado: 'active,notified' })
        setStockAlerts(data)
      } else {
        const estado = activeTab === 'activas' ? 'open,in_progress' : 'resolved,auto_resolved,closed'
        const data = await listIncidents({ estado })
        setIncidents(data)
      }
    } catch (error) {
      console.error('Error loading data:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleAnalyze = async (id: string) => {
    try {
      const updated = await analyzeIncident(id)
      upsertIncident(updated)
      await loadData()
      alert('✅ Análisis IA completado')
    } catch (error) {
      console.error('Error analyzing incident:', error)
      alert('❌ Error al analizar incidencia')
    }
  }

  const handleAutoResolve = async (id: string) => {
    try {
      const updated = await autoResolveIncident(id)
      upsertIncident(updated)
      await loadData()
      alert('✅ Incidencia auto-resuelta')
    } catch (error) {
      console.error('Error auto-resolving:', error)
      alert('❌ Error al auto-resolver')
    }
  }

  const handleAssign = async (id: string) => {
    const userId = profile?.user_id
    if (!userId) {
      alert('No se pudo obtener el ID de usuario')
      return
    }
    try {
      const updated = await assignIncident(id, userId)
      upsertIncident(updated)
      await loadData()
      alert('✅ Incidencia asignada')
    } catch (error) {
      console.error('Error assigning:', error)
      alert('❌ Error al asignar')
    }
  }

  const handleClose = async (id: string) => {
    if (!confirm('¿Cerrar esta incidencia?')) return
    try {
      const updated = await closeIncident(id)
      upsertIncident(updated)
      await loadData()
      alert('✅ Incidencia cerrada')
    } catch (error) {
      console.error('Error closing:', error)
      alert('❌ Error al cerrar')
    }
  }

  const handleNotifyStock = async (id: string) => {
    try {
      await notifyStockAlert(id)
      await loadData()
      alert('✅ Notificación enviada')
    } catch (error) {
      console.error('Error notifying:', error)
      alert('❌ Error al notificar')
    }
  }

  const handleResolveStock = async (id: string) => {
    try {
      await resolveStockAlert(id)
      await loadData()
      alert('✅ Alerta resuelta')
    } catch (error) {
      console.error('Error resolving stock alert:', error)
      alert('❌ Error al resolver')
    }
  }

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'critical': return 'bg-red-100 text-red-800 border-red-200'
      case 'high': return 'bg-orange-100 text-orange-800 border-orange-200'
      case 'medium': return 'bg-yellow-100 text-yellow-800 border-yellow-200'
      case 'low': return 'bg-blue-100 text-blue-800 border-blue-200'
      default: return 'bg-gray-100 text-gray-800 border-gray-200'
    }
  }

  const formatDate = (date: string) => {
    return new Date(date).toLocaleString('es-ES', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  return (
    <div className="admin-shell">
      <header className="mb-6">
        <div className="admin-header">
          <h1 className="admin-title">🚨 Panel de Incidencias</h1>
          <button
            onClick={loadData}
            className="btn btn-primary"
            disabled={loading}
          >
            {loading ? '⏳' : '🔄'} Actualizar
          </button>
        </div>
      </header>

      {/* Tabs */}
      <div className="mb-6 border-b border-gray-200">
        <div className="flex gap-4">
          <button
            onClick={() => setActiveTab('activas')}
            className={`pb-3 px-2 border-b-2 font-medium transition-colors ${
              activeTab === 'activas'
                ? 'border-blue-600 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            🔴 Activas ({activeTab === 'activas' ? incidents.length : '-'})
          </button>
          <button
            onClick={() => setActiveTab('resueltas')}
            className={`pb-3 px-2 border-b-2 font-medium transition-colors ${
              activeTab === 'resueltas'
                ? 'border-blue-600 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            ✅ Resueltas ({activeTab === 'resueltas' ? incidents.length : '-'})
          </button>
          <button
            onClick={() => setActiveTab('stock_alerts')}
            className={`pb-3 px-2 border-b-2 font-medium transition-colors ${
              activeTab === 'stock_alerts'
                ? 'border-blue-600 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            📦 Stock Alerts ({activeTab === 'stock_alerts' ? stockAlerts.length : '-'})
          </button>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin inline-block w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full"></div>
          <span className="ml-3 text-gray-600">Cargando</span>
        </div>
      ) : (
        <>
          {/* Tab: Activas / Resueltas */}
          {(activeTab === 'activas' || activeTab === 'resueltas') && (
            <div className="card overflow-hidden">
              {incidents.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  {activeTab === 'activas'
                    ? '🎉 No hay incidencias activas'
                    : 'No hay incidencias resueltas'
                  }
                </div>
              ) : (
                <div className="table-wrap"><table>
                    <thead >
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Severidad
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Título
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Empresa
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Tipo
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Estado
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Creada
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Acciones
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {incidents.map((incident) => (
                        <tr key={incident.id} className="hover:bg-gray-50">
                          <td className="px-4 py-3 whitespace-nowrap">
                            <span className={`px-2 py-1 text-xs font-bold rounded border ${getSeverityColor(incident.severidad)}`}>
                              {incident.severidad.toUpperCase()}
                            </span>
                          </td>
                          <td className="px-4 py-3">
                            <div className="text-sm font-medium text-gray-900">
                              {incident.titulo}
                              {incident.auto_detected && (
                                <span className="ml-2 text-xs bg-purple-100 text-purple-800 px-2 py-0.5 rounded">
                                  🤖 Auto-detect
                                </span>
                              )}
                            </div>
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-600 font-mono">
                            {incident.tenant_id?.substring(0, 8) || 'Sistema'}
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-600">
                            {incident.tipo}
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap">
                            <span className={`px-2 py-1 text-xs font-medium rounded ${
                              incident.auto_resolved
                                ? 'bg-green-100 text-green-800'
                                : incident.estado === 'resolved'
                                ? 'bg-green-100 text-green-800'
                                : incident.estado === 'in_progress'
                                ? 'bg-blue-100 text-blue-800'
                                : 'bg-gray-100 text-gray-800'
                            }`}>
                              {incident.auto_resolved ? '🤖 Auto-resuelto' : incident.estado}
                            </span>
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-600">
                            {formatDate(incident.created_at)}
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm">
                            <div className="flex gap-2">
                              <button
                                onClick={() => setSelectedIncident(incident)}
                                className="text-blue-600 hover:text-blue-800"
                                title="Ver detalle"
                              >
                                🔍
                              </button>
                              {activeTab === 'activas' && (
                                <>
                                  <button
                                    onClick={() => handleAnalyze(incident.id)}
                                    className="text-purple-600 hover:text-purple-800"
                                    title="Analizar con IA"
                                  >
                                    🤖
                                  </button>
                                  <button
                                    onClick={() => handleAutoResolve(incident.id)}
                                    className="text-green-600 hover:text-green-800"
                                    title="Auto-Resolver"
                                  >
                                    ✨
                                  </button>
                                  <button
                                    onClick={() => handleAssign(incident.id)}
                                    className="text-orange-600 hover:text-orange-800"
                                    title="Asignarme"
                                  >
                                    👤
                                  </button>
                                  <button
                                    onClick={() => handleClose(incident.id)}
                                    className="text-gray-600 hover:text-gray-800"
                                    title="Cerrar"
                                  >
                                    ✅
                                  </button>
                                </>
                              )}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}

          {/* Tab: Stock Alerts */}
          {activeTab === 'stock_alerts' && (
            <div className="card overflow-hidden">
              {stockAlerts.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  📦 No hay alertas de stock activas
                </div>
              ) : (
                <div className="table-wrap"><table>
                    <thead >
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Producto
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Almacén
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Stock Actual
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Mínimo
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Estado
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Detectada
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Acciones
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {stockAlerts.map((alert) => (
                        <tr key={alert.id} className="hover:bg-gray-50">
                          <td className="px-4 py-3">
                            <div className="text-sm font-medium text-gray-900">
                              {alert.product_name}
                            </div>
                            <div className="text-xs text-gray-500 font-mono">
                              {alert.product_id.substring(0, 8)}
                            </div>
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-600">
                            {alert.warehouse_name}
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap">
                            <span className={`text-sm font-bold ${
                              alert.qty_on_hand <= 0 ? 'text-red-600' : 'text-orange-600'
                            }`}>
                              {alert.qty_on_hand}
                            </span>
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-600">
                            {alert.min_qty}
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap">
                            <span className={`px-2 py-1 text-xs font-medium rounded ${
                              alert.estado === 'active' ? 'bg-red-100 text-red-800' :
                              alert.estado === 'notified' ? 'bg-yellow-100 text-yellow-800' :
                              'bg-green-100 text-green-800'
                            }`}>
                              {alert.estado}
                            </span>
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-600">
                            {formatDate(alert.detected_at)}
                          </td>
                          <td className="px-4 py-3 whitespace-nowrap text-sm">
                            <div className="flex gap-2">
                              <button
                                onClick={() => handleNotifyStock(alert.id)}
                                className="px-3 py-1 bg-blue-600 text-white rounded hover:bg-blue-700 text-xs"
                              >
                                📧 Notificar
                              </button>
                              <button
                                onClick={() => handleResolveStock(alert.id)}
                                className="px-3 py-1 bg-green-600 text-white rounded hover:bg-green-700 text-xs"
                              >
                                ✅ Resolver
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}
        </>
      )}

      {/* Modal Detalle */}
      {selectedIncident && (
        <IncidentDetailModal
          incident={selectedIncident}
          onClose={() => setSelectedIncident(null)}
          onAnalyze={handleAnalyze}
          onAutoResolve={handleAutoResolve}
          onAssign={handleAssign}
          onCloseIncident={handleClose}
        />
      )}
    </div>
  )
}

import React, { useState } from 'react'

import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'

import { useEnv } from '@ui/env'

import { useAuth } from '../auth/AuthContext'

export default function Login() {
  const { login } = useAuth()
  const navigate = useNavigate()
  const { tenantOrigin } = useEnv()
  const { t } = useTranslation()
  const [identificador, setIdentificador] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [submitting, setSubmitting] = useState(false)
  const year = new Date().getFullYear()

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)
    setSubmitting(true)
    try {
      await login({ identificador, password })
      navigate('/admin', { replace: true })
    } catch (err: any) {
      setError(err?.message || t('login.invalidCredentials'))
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <div className="gc-admin-login">
      {/* Background decoration */}
      <div className="gc-admin-login__bg" aria-hidden="true">
        <div className="gc-admin-login__orb gc-admin-login__orb--1" />
        <div className="gc-admin-login__orb gc-admin-login__orb--2" />
      </div>

      <div className="gc-admin-login__card">
        {/* Logo */}
        <div className="gc-admin-login__logo-wrap">
          <div className="gc-admin-login__logo">
            <svg viewBox="0 0 24 24" fill="none" className="gc-admin-login__logo-icon">
              <path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </div>
        </div>

        {/* Header */}
        <div className="gc-admin-login__header">
          <h1 className="gc-admin-login__title">{t('login.title')}</h1>
          <p className="gc-admin-login__subtitle">{t('login.adminSubtitle', { defaultValue: 'Panel de administración' })}</p>
        </div>

        {/* Form */}
        <form onSubmit={onSubmit} className="gc-admin-login__form">
          <div className="gc-admin-login__field">
            <label htmlFor="admin-identificador" className="gc-admin-login__label">{t('login.identifier')}</label>
            <input
              id="admin-identificador"
              name="identificador"
              className="gc-admin-login__input"
              value={identificador}
              onChange={e => setIdentificador(e.target.value)}
              autoComplete="username"
              placeholder="admin@gestiqcloud.com"
              required
            />
          </div>
          <div className="gc-admin-login__field">
            <label htmlFor="admin-password" className="gc-admin-login__label">{t('login.password')}</label>
            <input
              id="admin-password"
              name="password"
              type="password"
              className="gc-admin-login__input"
              value={password}
              onChange={e => setPassword(e.target.value)}
              autoComplete="current-password"
              placeholder="••••••••"
              required
            />
          </div>

          {error && (
            <div className="gc-admin-login__error" role="alert">
              <svg className="gc-admin-login__error-icon" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd"/>
              </svg>
              {error}
            </div>
          )}

          <button className="gc-admin-login__submit" type="submit" disabled={submitting}>
            {submitting ? (
              <svg className="gc-admin-login__spinner" viewBox="0 0 24 24" fill="none">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
              </svg>
            ) : null}
            {submitting ? t('login.submitting') : t('login.submit')}
          </button>
        </form>

        {/* Divider */}
        <div className="gc-admin-login__divider">
          <span>{t('login.tenantPrompt', { defaultValue: '¿Eres usuario de empresa?' })}</span>
        </div>

        <a href={`${tenantOrigin}/login`} className="gc-admin-login__tenant-link">
          {t('login.tenantLink', { defaultValue: 'Ir al login de empresa' })}
          <svg className="gc-admin-login__arrow" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z" clipRule="evenodd"/></svg>
        </a>

        <footer className="gc-admin-login__footer">
          © {year} GestiqCloud
        </footer>
      </div>
    </div>
  )
}

/**
 * LogsViewer.tsx
 * Dos tabs: Notificaciones (email/whatsapp/telegram) y Auditoría (create/update/delete)
 */

import React, { useState, useEffect, useCallback } from 'react'

import { useAuthGuard } from '../hooks/useAuthGuard'
import { listLogs, exportLogs, getLogStats, listAuditEvents, getAuditStats } from '../services/logs'

import type { LogEntry, LogFilters, LogStats, AuditEntry, AuditFilters, AuditStats } from '../types/logs'

type Tab = 'notifications' | 'audit'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
function formatDate(date: string) {
  return new Date(date).toLocaleString('es-ES', {
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
  })
}

const ACTION_COLORS: Record<string, string> = {
  create: 'bg-green-100 text-green-800',
  update: 'bg-blue-100 text-blue-800',
  delete: 'bg-red-100 text-red-800',
}

const ACTION_ICONS: Record<string, string> = {
  create: '✚',
  update: '✎',
  delete: '✕',
}

const NOTIF_TYPE_COLORS: Record<string, string> = {
  email: 'bg-indigo-100 text-indigo-800',
  whatsapp: 'bg-green-100 text-green-800',
  telegram: 'bg-blue-100 text-blue-800',
}

const STATUS_COLORS: Record<string, string> = {
  sent: 'bg-green-100 text-green-800',
  failed: 'bg-red-100 text-red-800',
  pending: 'bg-yellow-100 text-yellow-800',
}

function Badge({ text, colorClass }: { text: string; colorClass: string }) {
  return (
    <span className={`px-2 py-0.5 text-xs font-medium rounded ${colorClass}`}>
      {text}
    </span>
  )
}

// ---------------------------------------------------------------------------
// Tab: Auditoría
// ---------------------------------------------------------------------------
function AuditTab() {
  const [entries, setEntries] = useState<AuditEntry[]>([])
  const [stats, setStats] = useState<AuditStats | null>(null)
  const [loading, setLoading] = useState(true)
  const [selected, setSelected] = useState<AuditEntry | null>(null)

  const [filters, setFilters] = useState<AuditFilters>({
    tenant_id: '',
    action: 'all',
    entity_type: 'all',
    search: '',
    days: 7,
    page: 1,
    limit: 50,
  })

  const load = useCallback(async () => {
    setLoading(true)
    try {
      const [data, s] = await Promise.all([
        listAuditEvents(filters),
        getAuditStats({ tenant_id: filters.tenant_id, days: filters.days }),
      ])
      setEntries(data)
      setStats(s)
    } catch (e) {
      console.error('Error cargando auditoría:', e)
    } finally {
      setLoading(false)
    }
  }, [filters])

  useEffect(() => { load() }, [load])

  const set = (key: keyof AuditFilters, value: any) =>
    setFilters(prev => ({ ...prev, [key]: value, page: key === 'page' ? value : 1 }))

  const entityTypes = stats
    ? Object.keys(stats.by_entity_type).sort()
    : []

  return (
    <div>
      {/* Stats */}
      {stats && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
          <div className="card">
            <div className="text-xs text-gray-500 mb-1">Total acciones ({stats.period_days}d)</div>
            <div className="text-2xl font-bold text-gray-900">{stats.total.toLocaleString()}</div>
          </div>
          <div className="card">
            <div className="text-xs text-gray-500 mb-1">Creaciones</div>
            <div className="text-2xl font-bold text-green-600">{stats.by_action.create ?? 0}</div>
          </div>
          <div className="card">
            <div className="text-xs text-gray-500 mb-1">Actualizaciones</div>
            <div className="text-2xl font-bold text-blue-600">{stats.by_action.update ?? 0}</div>
          </div>
          <div className="card">
            <div className="text-xs text-gray-500 mb-1">Eliminaciones</div>
            <div className="text-2xl font-bold text-red-600">{stats.by_action.delete ?? 0}</div>
          </div>
        </div>
      )}

      {/* Top tenants */}
      {stats && stats.by_tenant.length > 0 && !filters.tenant_id && (
        <div className="card mb-6">
          <div className="text-xs font-semibold text-gray-500 uppercase mb-2">Tenants más activos</div>
          <div className="flex flex-wrap gap-2">
            {stats.by_tenant.map(t => (
              <button
                key={t.tenant_id ?? 'sistema'}
                onClick={() => set('tenant_id', t.tenant_id ?? '')}
                className="px-3 py-1 bg-gray-100 hover:bg-blue-100 hover:text-blue-700 rounded-full text-sm transition-colors"
              >
                {t.tenant_name ?? t.tenant_id ?? 'sistema'}
                <span className="ml-1 font-bold">{t.total}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Filtros */}
      <div className="card mb-6">
        <h3 className="font-semibold mb-3 text-gray-900">Filtros</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          <div className="lg:col-span-2">
            <label className="block text-xs font-medium text-gray-600 mb-1">Tenant ID (UUID o nombre)</label>
            <input
              type="text"
              value={filters.tenant_id}
              onChange={e => set('tenant_id', e.target.value.trim())}
              placeholder="Pegar UUID del tenant…"
              className="input font-mono text-sm"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">Acción</label>
            <select value={filters.action} onChange={e => set('action', e.target.value)} className="input">
              <option value="all">Todas</option>
              <option value="create">Crear</option>
              <option value="update">Actualizar</option>
              <option value="delete">Eliminar</option>
            </select>
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">Entidad</label>
            <select value={filters.entity_type} onChange={e => set('entity_type', e.target.value)} className="input">
              <option value="all">Todas</option>
              {entityTypes.map(et => (
                <option key={et} value={et}>{et}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">Días hacia atrás</label>
            <input
              type="number" min={1} max={365}
              value={filters.days}
              onChange={e => set('days', Number(e.target.value))}
              className="input"
            />
          </div>
        </div>
        <div className="mt-3 flex gap-3 items-center">
          <input
            type="text"
            value={filters.search}
            onChange={e => set('search', e.target.value)}
            placeholder="Buscar por ID de entidad o tipo…"
            className="input flex-1"
          />
          {filters.tenant_id && (
            <button
              onClick={() => set('tenant_id', '')}
              className="text-sm text-gray-500 hover:text-red-600"
            >
              Limpiar tenant
            </button>
          )}
        </div>
      </div>

      {/* Tabla */}
      <div className="bg-white rounded-lg shadow border border-gray-200 overflow-hidden">
        {loading && entries.length === 0 ? (
          <div className="p-8 text-center text-gray-500">
            <div className="animate-spin inline-block w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full mb-2" />
            <div>Cargando auditoría…</div>
          </div>
        ) : entries.length === 0 ? (
          <div className="p-8 text-center text-gray-500">
            Sin resultados con los filtros aplicados
          </div>
        ) : (
          <>
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200 text-sm">
                <thead className="bg-gray-50">
                  <tr>
                    {['Fecha/Hora', 'Tenant', 'Acción', 'Entidad', 'ID Entidad', 'Usuario', 'IP', 'Cambios'].map(h => (
                      <th key={h} className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider whitespace-nowrap">
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {entries.map(ev => (
                    <tr key={ev.id} className="hover:bg-gray-50">
                      <td className="px-4 py-2 whitespace-nowrap text-gray-700">{formatDate(ev.created_at)}</td>
                      <td className="px-4 py-2 whitespace-nowrap">
                        {ev.tenant_name ? (
                          <button
                            className="text-blue-600 hover:underline font-medium"
                            onClick={() => set('tenant_id', ev.tenant_id ?? '')}
                            title={ev.tenant_id ?? ''}
                          >
                            {ev.tenant_name}
                          </button>
                        ) : (
                          <span className="text-gray-400 text-xs font-mono">
                            {ev.tenant_id?.slice(0, 8) ?? 'sistema'}
                          </span>
                        )}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap">
                        <Badge
                          text={`${ACTION_ICONS[ev.action] ?? ''} ${ev.action}`}
                          colorClass={ACTION_COLORS[ev.action] ?? 'bg-gray-100 text-gray-700'}
                        />
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-gray-900 font-medium">{ev.entity_type}</td>
                      <td className="px-4 py-2 whitespace-nowrap font-mono text-xs text-gray-500">
                        {ev.entity_id ? ev.entity_id.slice(0, 12) + (ev.entity_id.length > 12 ? '…' : '') : '—'}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap font-mono text-xs text-gray-500">
                        {ev.user_id ? ev.user_id.slice(0, 8) + '…' : (
                          <span className="text-gray-400">sistema</span>
                        )}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-xs text-gray-400">{ev.ip ?? '—'}</td>
                      <td className="px-4 py-2 whitespace-nowrap">
                        {ev.changes && Object.keys(ev.changes).length > 0 ? (
                          <button
                            onClick={() => setSelected(ev)}
                            className="text-blue-600 hover:text-blue-800 font-medium text-xs"
                          >
                            Ver cambios ({Object.keys(ev.changes).length})
                          </button>
                        ) : (
                          <span className="text-gray-400 text-xs">—</span>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="bg-gray-50 px-4 py-3 border-t border-gray-200 flex items-center justify-between">
              <div className="text-sm text-gray-600">
                {entries.length} registros · últimos {filters.days} días
                {filters.tenant_id && <span className="ml-2 font-medium text-blue-600">· filtrado por tenant</span>}
              </div>
              <div className="flex gap-2">
                <button
                  onClick={() => set('page', Math.max(1, filters.page - 1))}
                  disabled={filters.page === 1}
                  className="px-3 py-1 bg-white border border-gray-300 rounded hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed text-sm"
                >
                  ← Anterior
                </button>
                <span className="px-3 py-1 bg-white border border-gray-300 rounded text-sm">
                  Pág {filters.page}
                </span>
                <button
                  onClick={() => set('page', filters.page + 1)}
                  disabled={entries.length < filters.limit}
                  className="px-3 py-1 bg-white border border-gray-300 rounded hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed text-sm"
                >
                  Siguiente →
                </button>
              </div>
            </div>
          </>
        )}
      </div>

      {/* Modal cambios */}
      {selected && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-3xl w-full max-h-[90vh] overflow-hidden flex flex-col">
            <div className="p-4 border-b border-gray-200 flex items-center justify-between">
              <div>
                <h3 className="text-lg font-semibold">
                  {ACTION_ICONS[selected.action]} {selected.action} · {selected.entity_type}
                </h3>
                <p className="text-sm text-gray-500">
                  {selected.tenant_name ?? selected.tenant_id ?? 'sistema'} · {formatDate(selected.created_at)}
                </p>
              </div>
              <button onClick={() => setSelected(null)} className="text-gray-400 hover:text-gray-600 text-xl">✕</button>
            </div>
            <div className="p-4 overflow-y-auto flex-1">
              {selected.changes && Object.keys(selected.changes).length > 0 ? (
                <table className="w-full text-sm border border-gray-200 rounded">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-3 py-2 text-left font-medium text-gray-600 w-1/4">Campo</th>
                      <th className="px-3 py-2 text-left font-medium text-gray-600 w-[37.5%]">Antes</th>
                      <th className="px-3 py-2 text-left font-medium text-gray-600 w-[37.5%]">Después</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {Object.entries(selected.changes).map(([field, diff]) => (
                      <tr key={field} className="hover:bg-gray-50">
                        <td className="px-3 py-2 font-mono text-xs text-gray-700 font-semibold">{field}</td>
                        <td className="px-3 py-2 font-mono text-xs text-red-700 bg-red-50 break-all">
                          {diff.old === null || diff.old === undefined ? <span className="text-gray-400 italic">null</span> : String(diff.old)}
                        </td>
                        <td className="px-3 py-2 font-mono text-xs text-green-700 bg-green-50 break-all">
                          {diff.new === null || diff.new === undefined ? <span className="text-gray-400 italic">null</span> : String(diff.new)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                <pre className="bg-gray-900 text-green-400 p-4 rounded text-sm font-mono overflow-x-auto">
                  {JSON.stringify(selected, null, 2)}
                </pre>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

