import React, { useCallback, useEffect, useRef, useState } from 'react'
import './Migrations.css'

import {
  getMigrationDetails,
  getMigrationHistory,
  getMigrationsList,
  markMigration,
  runMigrations,
  type MigrationHistoryItem,
  type MigrationRecord,
} from '../services/ops'

// ─── helpers ──────────────────────────────────────────────────────────────────

function friendlyName(version: string, name: string | null): string {
  const raw = name || version
  return raw.replace(/^\d{4}-\d{2}-\d{2}_\d+_/, '').replace(/_/g, ' ')
}

function fmtDate(d: string | null | undefined): string {
  if (!d) return '—'
  return new Date(d).toLocaleString('es', { dateStyle: 'short', timeStyle: 'short' })
}

// ─── small components ─────────────────────────────────────────────────────────

function Chevron({ open }: { open: boolean }) {
  return (
    <svg className={`mig-chevron${open ? ' mig-chevron--open' : ''}`} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
    </svg>
  )
}

function Spinner() {
  return <span className="mig-spinner" />
}

function Badge({ status }: { status: string }) {
  const labels: Record<string, string> = {
    success: 'Aplicada', pending: 'Pendiente', failed: 'Fallida', ignored: 'Ignorada', running: 'Ejecutando',
  }
  return (
    <span className={`mig-badge mig-badge--${status}`}>
      {labels[status] ?? status}
    </span>
  )
}

function Toast({ msg, isError, onDismiss }: { msg: string; isError: boolean; onDismiss: () => void }) {
  useEffect(() => {
    if (!isError) {
      const t = setTimeout(onDismiss, 4000)
      return () => clearTimeout(t)
    }
  }, [msg, isError, onDismiss])
  return (
    <div className={`mig-toast ${isError ? 'mig-toast--error' : 'mig-toast--ok'}`}>
      <span>{msg}</span>
      <button className="mig-toast__dismiss" onClick={onDismiss}>×</button>
    </div>
  )
}

// ─── section ─────────────────────────────────────────────────────────────────

function Section({
  title, count, variant = 'default', defaultOpen = true, children,
}: {
  title: string
  count: number
  variant?: 'default' | 'pending' | 'failed'
  defaultOpen?: boolean
  children: React.ReactNode
}) {
  const [open, setOpen] = useState(defaultOpen)
  const variantCls = variant !== 'default' ? ` mig-section-toggle--${variant}` : ''
  return (
    <div className="mig-section">
      <button className={`mig-section-toggle${variantCls}`} onClick={() => setOpen(o => !o)}>
        <span className="mig-section-toggle__left">
          <Chevron open={open} />
          {title}
        </span>
        <span className="mig-section-toggle__count">{count}</span>
      </button>
      {open && children}
    </div>
  )
}

// ─── action row ───────────────────────────────────────────────────────────────

function ActionRow({
  rec, marking, expandedError, onToggleError, onMark,
}: {
  rec: MigrationRecord
  marking: boolean
  expandedError: boolean
  onToggleError: () => void
  onMark: (rec: MigrationRecord, s: 'ignored' | 'pending') => void
}) {
  return (
    <div className="mig-action-row">
      <div className="mig-action-row__inner">
        <div className="mig-action-row__body">
          <div className="mig-action-row__name">
            <Badge status={rec.status} />
            <span className="mig-action-row__title">{friendlyName(rec.version, rec.name)}</span>
          </div>
          <div className="mig-action-row__meta">
            <span className="mig-action-row__version">{rec.version}</span>
            {rec.completed_at && <span>Aplicada {fmtDate(rec.completed_at)}</span>}
          </div>
          {rec.error_message && (
            <>
              <button className="mig-error-toggle" onClick={onToggleError}>
                <Chevron open={expandedError} />
                {expandedError ? 'Ocultar error' : 'Ver error'}
              </button>
              {expandedError && <pre className="mig-error-pre">{rec.error_message}</pre>}
            </>
          )}
        </div>
        <div className="mig-action-row__actions">
          {rec.status !== 'ignored' && (
            <button className="mig-btn--sm" disabled={marking} onClick={() => onMark(rec, 'ignored')}>
              Ignorar
            </button>
          )}
          {(rec.status === 'failed' || rec.status === 'ignored') && (
            <button className="mig-btn--sm mig-btn--sm-warn" disabled={marking} onClick={() => onMark(rec, 'pending')}>
              Reintentar
            </button>
          )}
        </div>
      </div>
    </div>
  )
}

// ─── applied table ────────────────────────────────────────────────────────────

function AppliedTable({
  migrations, marking, onMark,
}: {
  migrations: MigrationRecord[]
  marking: number | null
  onMark: (rec: MigrationRecord, s: 'ignored' | 'pending') => void
}) {
  const [search, setSearch] = useState('')
  const filtered = search
    ? migrations.filter(m =>
        friendlyName(m.version, m.name).toLowerCase().includes(search.toLowerCase()) ||
        m.version.toLowerCase().includes(search.toLowerCase()),
      )
    : migrations

  return (
    <div className="mig-card">
      {migrations.length > 8 && (
        <div className="mig-table-search">
          <input
            type="search"
            placeholder="Buscar migración..."
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>
      )}
      <table className="mig-table">
        <tbody>
          {filtered.map(m => (
            <tr key={m.id}>
              <td className="mig-table__name">{friendlyName(m.version, m.name)}</td>
              <td className="mig-table__version">{m.version}</td>
              <td className="mig-table__date">{fmtDate(m.completed_at)}</td>
              <td className="mig-table__action">
                <button
                  className="mig-table__ignore-btn"
                  disabled={marking === m.id}
                  onClick={() => onMark(m, 'ignored')}
                >
                  ignorar
                </button>
              </td>
            </tr>
          ))}
          {filtered.length === 0 && (
            <tr><td colSpan={4} className="mig-table__empty">Sin resultados para &quot;{search}&quot;</td></tr>
          )}
        </tbody>
      </table>
    </div>
  )
}

// ─── page ─────────────────────────────────────────────────────────────────────

export default function Migraciones() {
  const [loading, setLoading]   = useState(true)
  const [running, setRunning]   = useState(false)
  const [msg, setMsg]           = useState<string | null>(null)
  const [isError, setIsError]   = useState(false)
  const [migrations, setMigrations] = useState<MigrationRecord[]>([])
  const [runHistory, setRunHistory] = useState<MigrationHistoryItem[]>([])
  const [marking, setMarking]   = useState<number | null>(null)
  const [showHistory, setShowHistory] = useState(false)
  const [expandedError, setExpandedError] = useState<number | null>(null)
  const pollingRef = useRef<ReturnType<typeof setInterval> | null>(null)

  const dismissMsg = useCallback(() => setMsg(null), [])

  const reload = useCallback(async () => {
    try {
      const [list, hist, details] = await Promise.allSettled([
        getMigrationsList(500),
        getMigrationHistory(20),
        getMigrationDetails(),
      ])

      let records: MigrationRecord[] = list.status === 'fulfilled' ? list.value : []

      // Migraciones en disco no registradas en schema_migrations → aparecen como pendientes
      if (details.status === 'fulfilled' && Array.isArray(details.value?.pending_revisions)) {
        const knownVersions = new Set(records.map(r => r.version))
        const synthetic: MigrationRecord[] = details.value.pending_revisions
          .filter((v: string) => !knownVersions.has(v))
          .map((v: string, i: number) => ({
            id: -(i + 1),
            version: v,
            name: v,
            status: 'pending',
            mode: null,
            started_at: null,
            completed_at: null,
            executed_by: null,
            execution_time_ms: null,
            error_message: null,
            applied_order: null,
            created_at: null,
          }))
        if (synthetic.length > 0) records = [...synthetic, ...records]
      }

      setMigrations(records)
      if (hist.status === 'fulfilled' && hist.value?.items) setRunHistory(hist.value.items)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => { void reload() }, [reload])
  useEffect(() => () => { if (pollingRef.current) clearInterval(pollingRef.current) }, [])

  async function onRun() {
    setRunning(true)
    setMsg(null)
    setIsError(false)
    try {
      const res = await runMigrations()
      if (res?.message === 'sin_migraciones_pendientes') {
        setMsg('Sin migraciones pendientes')
        setRunning(false)
        return
      }
      if (!res?.ok) {
        setMsg('No se pudo iniciar el runner')
        setIsError(true)
        setRunning(false)
        return
      }
      setMsg('Ejecutando migraciones...')
      pollingRef.current = setInterval(async () => {
        const d = await getMigrationDetails().catch(() => null)
        await reload()
        if (!d?.running) {
          clearInterval(pollingRef.current!)
          pollingRef.current = null
          setRunning(false)
          setMsg('Migraciones completadas')
          setIsError(false)
        }
      }, 3000)
    } catch (e: any) {
      setIsError(true)
      setMsg(e?.status === 409 ? 'Ya hay una migración en curso' : `Error: ${e?.message || 'desconocido'}`)
      setRunning(false)
    }
  }

  async function onMark(rec: MigrationRecord, newStatus: 'ignored' | 'pending') {
    setMarking(rec.id)
    try {
      await markMigration(rec.version, newStatus)
      await reload()
    } catch {
      setMsg('No se pudo actualizar el estado')
      setIsError(true)
    } finally {
      setMarking(null)
    }
  }

  const pendingMigs = migrations.filter(m => m.status === 'pending')
  const failedMigs  = migrations.filter(m => m.status === 'failed')
  const appliedMigs = migrations.filter(m => m.status === 'success')
  const ignoredMigs = migrations.filter(m => m.status === 'ignored')
  const allGood = !loading && pendingMigs.length === 0 && failedMigs.length === 0

  const rowProps = (m: MigrationRecord) => ({
    rec: m,
    marking: marking === m.id,
    expandedError: expandedError === m.id,
    onToggleError: () => setExpandedError(prev => prev === m.id ? null : m.id),
    onMark,
  })

  return (
    <div className="mig-page">

      {/* Header */}
      <div className="mig-header">
        <div>
          <h2>Migraciones</h2>
          <p>Base de datos · runner idempotente</p>
        </div>
        <div className="mig-header-actions">
          <button
            className="mig-btn mig-btn--ghost"
            disabled={loading}
            onClick={() => void reload()}
          >
            {loading ? <Spinner /> : 'Refrescar'}
          </button>
          <button
            className="mig-btn mig-btn--primary"
            disabled={running || loading || pendingMigs.length === 0}
            onClick={onRun}
          >
            {running && <Spinner />}
            {running
              ? 'Ejecutando...'
              : pendingMigs.length > 0
              ? `Ejecutar ${pendingMigs.length} pendiente${pendingMigs.length > 1 ? 's' : ''}`
              : 'Al día'}
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="mig-stats">
        <div className="mig-stat mig-stat--success">
          <div className="mig-stat__value">{appliedMigs.length}</div>
          <div className="mig-stat__label">Aplicadas</div>
        </div>
        <div className={`mig-stat${pendingMigs.length > 0 ? ' mig-stat--warning' : ''}`}>
          <div className="mig-stat__value">{pendingMigs.length}</div>
          <div className="mig-stat__label">Pendientes</div>
        </div>
        <div className={`mig-stat${failedMigs.length > 0 ? ' mig-stat--danger' : ''}`}>
          <div className="mig-stat__value">{failedMigs.length}</div>
          <div className="mig-stat__label">Fallidas</div>
        </div>
        <div className="mig-stat">
          <div className="mig-stat__value">{ignoredMigs.length}</div>
          <div className="mig-stat__label">Ignoradas</div>
        </div>
      </div>

      {/* Toast */}
      {msg && <Toast msg={msg} isError={isError} onDismiss={dismissMsg} />}

      {/* Skeleton */}
      {loading && (
        <div className="mig-skeleton">
          {[...Array(4)].map((_, i) => <div key={i} className="mig-skeleton__bar" />)}
        </div>
      )}

      {/* All good */}
      {allGood && !loading && (
        <div className="mig-allgood">
          <div className="mig-allgood__icon">✓</div>
          <div>
            <p className="mig-allgood__title">Todo al día</p>
            <p className="mig-allgood__sub">
              {appliedMigs.length} migración{appliedMigs.length !== 1 ? 'es' : ''} aplicada{appliedMigs.length !== 1 ? 's' : ''} correctamente
            </p>
          </div>
        </div>
      )}

      {/* Failed */}
      {!loading && failedMigs.length > 0 && (
        <Section title="Fallidas" count={failedMigs.length} variant="failed">
          <div className="mig-card mig-card--failed">
            {failedMigs.map(m => <ActionRow key={m.id} {...rowProps(m)} />)}
          </div>
        </Section>
      )}

      {/* Pending */}
      {!loading && pendingMigs.length > 0 && (
        <Section title="Pendientes" count={pendingMigs.length} variant="pending">
          <div className="mig-card mig-card--pending">
            {pendingMigs.map(m => <ActionRow key={m.id} {...rowProps(m)} />)}
          </div>
        </Section>
      )}

      {/* Applied — collapsed by default */}
      {!loading && appliedMigs.length > 0 && (
        <Section title="Aplicadas" count={appliedMigs.length} defaultOpen={false}>
          <AppliedTable migrations={appliedMigs} marking={marking} onMark={onMark} />
        </Section>
      )}

      {/* Ignored — collapsed by default */}
      {!loading && ignoredMigs.length > 0 && (
        <Section title="Ignoradas" count={ignoredMigs.length} defaultOpen={false}>
          <div className="mig-card">
            {ignoredMigs.map(m => <ActionRow key={m.id} {...rowProps(m)} />)}
          </div>
        </Section>
      )}

      {/* Run history */}
      {!loading && runHistory.length > 0 && (
        <>
          <button className="mig-history-toggle" onClick={() => setShowHistory(h => !h)}>
            <Chevron open={showHistory} />
            Historial de ejecuciones ({runHistory.length})
          </button>
          {showHistory && (
            <div className="mig-card" style={{ marginTop: '0.375rem' }}>
              <table className="mig-table">
                <thead>
                  <tr style={{ background: 'var(--gc-bg)', color: 'var(--gc-muted)', fontSize: '0.75rem', fontWeight: 600 }}>
                    <td style={{ padding: '0.5rem 1rem', borderBottom: '1px solid var(--gc-border)' }}>Inicio</td>
                    <td style={{ padding: '0.5rem 1rem', borderBottom: '1px solid var(--gc-border)' }}>Fin</td>
                    <td style={{ padding: '0.5rem 1rem', borderBottom: '1px solid var(--gc-border)' }}>Modo</td>
                    <td style={{ padding: '0.5rem 1rem', borderBottom: '1px solid var(--gc-border)' }}>Estado</td>
                    <td style={{ padding: '0.5rem 1rem', borderBottom: '1px solid var(--gc-border)' }}>Error</td>
                  </tr>
                </thead>
                <tbody>
                  {runHistory.map(h => (
                    <tr key={h.id}>
                      <td className="mig-table__date">{fmtDate(h.started_at)}</td>
                      <td className="mig-table__date">{fmtDate(h.finished_at)}</td>
                      <td className="mig-table__version">{h.mode || '—'}</td>
                      <td>
                        {h.ok === true
                          ? <Badge status="success" />
                          : h.ok === false
                          ? <Badge status="failed" />
                          : '—'}
                      </td>
                      <td className="mig-table__date" style={{ color: 'var(--gc-danger)', maxWidth: 240, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                        {h.error || '—'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}
    </div>
  )
}

import React, { useEffect, useState } from 'react'

import { useAuthGuard } from '../hooks/useAuthGuard'
import {
  listUsuarios,
  reenviarReset,
  activarUsuario,
  desactivarUsuario,
  desactivarEmpresa,
  setPasswordDirect,
  type AdminUsuario,
} from '../services/usuarios'
import { useToast, getErrorMessage } from '../shared/toast'

const AVATAR_COLORS = [
  'bg-violet-100 text-violet-700',
  'bg-blue-100 text-blue-700',
  'bg-emerald-100 text-emerald-700',
  'bg-amber-100 text-amber-700',
  'bg-rose-100 text-rose-700',
  'bg-cyan-100 text-cyan-700',
]

function avatarColor(str: string) {
  let hash = 0
  for (let i = 0; i < str.length; i++) hash = str.charCodeAt(i) + ((hash << 5) - hash)
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length]
}

export default function Usuarios() {
  useAuthGuard('superadmin')
  const [items, setItems] = useState<AdminUsuario[]>([])
  const [query, setQuery] = useState('')
  const [loading, setLoading] = useState(false)
  const [errMsg, setErrMsg] = useState<string | null>(null)
  const [confirmEmpresaId, setConfirmEmpresaId] = useState<number | string | null>(null)
  const [setPwdUserId, setSetPwdUserId] = useState<number | string | null>(null)
  const [setPwdUser, setSetPwdUser] = useState<AdminUsuario | null>(null)
  const [newPwd, setNewPwd] = useState('')
  const [showPwd, setShowPwd] = useState(false)
  const { success, error: toastError } = useToast()

  const load = async () => {
    try {
      setLoading(true)
      const data = await listUsuarios()
      const normalized = (data || []).map((u) => ({
        ...u,
        name: u.name || '',
        email: u.email || '',
        username: u.username || '',
        is_company_admin: u.is_company_admin ?? false,
        active: u.active ?? false,
      }))
      setItems(normalized)
    } catch (e: any) {
      const m = getErrorMessage(e)
      setErrMsg(m)
      toastError(m)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { load() }, [])

  const filtered = items.filter((u) => {
    const q = query.toLowerCase()
    return (
      `${u.name || ''}`.toLowerCase().includes(q) ||
      `${u.email || ''}`.toLowerCase().includes(q) ||
      `${u.username || ''}`.toLowerCase().includes(q)
    )
  })

  const activeCount = items.filter((u) => u.active).length

  return (
    <div className="mx-auto max-w-6xl space-y-6 px-4 py-8">

      {/* Header */}
      <div className="flex flex-col gap-1 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Usuarios principales</h1>
          <p className="mt-0.5 text-sm text-gray-500">
            Administradores de empresa registrados en la plataforma
          </p>
        </div>
        <div className="flex items-center gap-3">
          <span className="rounded-full bg-gray-100 px-3 py-1 text-sm font-medium text-gray-600">
            {items.length} usuarios
          </span>
          <span className="rounded-full bg-green-100 px-3 py-1 text-sm font-medium text-green-700">
            {activeCount} activos
          </span>
        </div>
      </div>

      {/* Search */}
      <div className="relative">
        <svg className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" width="16" height="16" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-4.35-4.35M17 11A6 6 0 1 1 5 11a6 6 0 0 1 12 0z" />
        </svg>
        <input
          type="text"
          placeholder="Buscar por nombre, usuario o correo…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="w-full rounded-lg border border-gray-200 bg-white py-2.5 pl-9 pr-4 text-sm shadow-sm focus:border-blue-400 focus:outline-none focus:ring-2 focus:ring-blue-100"
        />
      </div>

      {loading && (
        <div className="flex items-center gap-2 text-sm text-gray-400">
          <svg className="animate-spin" width="16" height="16" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z" />
          </svg>
          Cargando…
        </div>
      )}
      {errMsg && (
        <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
          <svg width="16" height="16" className="shrink-0" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm-.75-11.25a.75.75 0 011.5 0v4a.75.75 0 01-1.5 0v-4zm.75 7a1 1 0 100-2 1 1 0 000 2z" clipRule="evenodd" />
          </svg>
          {errMsg}
        </div>
      )}

      {/* Table */}
      {!loading && filtered.length > 0 && (
        <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-gray-100 bg-gray-50 text-left text-xs font-medium uppercase tracking-wider text-gray-500">
                <th className="px-5 py-3">Usuario</th>
                <th className="hidden px-5 py-3 sm:table-cell">Contacto</th>
                <th className="px-5 py-3">Estado</th>
                <th className="px-5 py-3 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filtered.map((u) => {
                const initials = (u.name || u.email || '?').charAt(0).toUpperCase()
                const color = avatarColor(u.email || u.name || String(u.id))
                return (
                  <tr key={u.id} className="group transition-colors hover:bg-gray-50/60">
                    {/* Usuario */}
                    <td className="px-5 py-4">
                      <div className="flex items-center gap-3">
                        <div className={`grid h-9 w-9 shrink-0 place-items-center rounded-full text-sm font-semibold ${color}`}>
                          {initials}
                        </div>
                        <div className="min-w-0">
                          <p className="truncate font-medium text-gray-900">
                            {u.username ? `@${u.username}` : <span className="text-gray-400 italic">sin usuario</span>}
                          </p>
                          <p className="truncate text-xs text-gray-500">
                            {u.name || <span className="italic">Sin nombre</span>}
                          </p>
                        </div>
                      </div>
                    </td>
                    {/* Contacto */}
                    <td className="hidden px-5 py-4 sm:table-cell">
                      <span className="text-gray-600">{u.email || '-'}</span>
                    </td>
                    {/* Estado */}
                    <td className="px-5 py-4">
                      {u.active ? (
                        <span className="inline-flex items-center gap-1.5 rounded-full bg-green-100 px-2.5 py-1 text-xs font-medium text-green-700">
                          <span className="h-1.5 w-1.5 rounded-full bg-green-500" />
                          Activo
                        </span>
                      ) : (
                        <span className="inline-flex items-center gap-1.5 rounded-full bg-gray-100 px-2.5 py-1 text-xs font-medium text-gray-500">
                          <span className="h-1.5 w-1.5 rounded-full bg-gray-400" />
                          Inactivo
                        </span>
                      )}
                    </td>
                    {/* Acciones */}
                    <td className="px-5 py-4">
                      <div className="flex flex-wrap items-center justify-end gap-1.5">
                        <button
                          title="Reenviar correo de reset"
                          onClick={async () => {
                            try { await reenviarReset(u.id); success('Correo de restablecimiento enviado') }
                            catch (e: any) { toastError(getErrorMessage(e)) }
                          }}
                          className="rounded-md border border-gray-200 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-600 shadow-sm transition hover:border-purple-300 hover:bg-purple-50 hover:text-purple-700"
                        >
                          Reenviar correo
                        </button>
                        <button
                          title="Establecer contraseña"
                          onClick={() => { setSetPwdUserId(u.id); setSetPwdUser(u); setNewPwd(''); setShowPwd(false) }}
                          className="rounded-md border border-gray-200 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-600 shadow-sm transition hover:border-blue-300 hover:bg-blue-50 hover:text-blue-700"
                        >
                          Contraseña
                        </button>
                        {u.active ? (
                          <>
                            <button
                              onClick={async () => {
                                try { await desactivarUsuario(u.id); success('Usuario desactivado'); load() }
                                catch (e: any) { toastError(getErrorMessage(e)) }
                              }}
                              className="rounded-md border border-gray-200 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-600 shadow-sm transition hover:border-amber-300 hover:bg-amber-50 hover:text-amber-700"
                            >
                              Desactivar
                            </button>
                            <button
                              onClick={() => setConfirmEmpresaId(u.id)}
                              className="rounded-md border border-gray-200 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-600 shadow-sm transition hover:border-red-300 hover:bg-red-50 hover:text-red-700"
                            >
                              Eliminar
                            </button>
                          </>
                        ) : (
                          <button
                            onClick={async () => {
                              try { await activarUsuario(u.id); success('Usuario activado'); load() }
                              catch (e: any) { toastError(getErrorMessage(e)) }
                            }}
                            className="rounded-md border border-gray-200 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-600 shadow-sm transition hover:border-green-300 hover:bg-green-50 hover:text-green-700"
                          >
                            Activar
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      )}

      {!loading && filtered.length === 0 && (
        <div className="rounded-xl border border-dashed border-gray-200 bg-gray-50 py-16 text-center">
          <p className="text-sm text-gray-400">No hay usuarios que coincidan con la búsqueda.</p>
        </div>
      )}

      {/* Modal: confirmar acción sobre empresa */}
      {confirmEmpresaId !== null && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4">
          <div className="w-full max-w-md space-y-4 rounded-2xl bg-white p-6 shadow-xl">
            <div className="flex items-start gap-3">
              <div className="grid h-10 w-10 shrink-0 place-items-center rounded-full bg-amber-100 text-amber-600">
                <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z" />
                </svg>
              </div>
              <div>
                <h2 className="font-semibold text-gray-900">Acción sobre empresa</h2>
                <p className="mt-1 text-sm text-gray-500">
                  Este usuario es el administrador principal. Puedes asignar otro usuario o desactivar la empresa completa.
                </p>
              </div>
            </div>
            <div className="space-y-2 pt-1">
              <a
                href={`/admin/users/${confirmEmpresaId}/assign-new-admin`}
                className="block rounded-lg bg-blue-600 px-4 py-2.5 text-center text-sm font-medium text-white hover:bg-blue-700"
              >
                Asignar otro administrador
              </a>
              <button
                onClick={async () => {
                  try { await desactivarEmpresa(confirmEmpresaId!); success('Empresa desactivada'); setConfirmEmpresaId(null); load() }
                  catch (e: any) { toastError(getErrorMessage(e)) }
                }}
                className="w-full rounded-lg border border-red-200 bg-red-50 px-4 py-2.5 text-sm font-medium text-red-700 hover:bg-red-100"
              >
                Desactivar empresa
              </button>
              <button
                onClick={() => setConfirmEmpresaId(null)}
                className="w-full py-2 text-sm text-gray-500 hover:text-gray-800"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: establecer contraseña */}
      {setPwdUserId !== null && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4">
          <div className="w-full max-w-sm space-y-4 rounded-2xl bg-white p-6 shadow-xl">
            <div>
              <h3 className="font-semibold text-gray-900">Establecer contraseña</h3>
              <p className="mt-0.5 text-sm text-gray-500">Define una contraseña temporal para este usuario.</p>
            </div>
            {setPwdUser && (
              <div className="flex items-center gap-3 rounded-lg border border-gray-100 bg-gray-50 p-3">
                <div className={`grid h-8 w-8 shrink-0 place-items-center rounded-full text-xs font-semibold ${avatarColor(setPwdUser.email || setPwdUser.name || String(setPwdUser.id))}`}>
                  {(setPwdUser.name || setPwdUser.email || '?').charAt(0).toUpperCase()}
                </div>
                <div className="min-w-0">
                  <p className="truncate text-sm font-medium text-gray-800">{setPwdUser.name || setPwdUser.email}</p>
                  {setPwdUser.username && <p className="text-xs text-gray-400">@{setPwdUser.username}</p>}
                </div>
              </div>
            )}
            <div className="relative">
              <input
                type={showPwd ? 'text' : 'password'}
                value={newPwd}
                onChange={(e) => setNewPwd(e.target.value)}
                placeholder="Nueva contraseña (mín. 8 caracteres)"
                className="w-full rounded-lg border border-gray-200 px-3 py-2.5 pr-10 text-sm focus:border-blue-400 focus:outline-none focus:ring-2 focus:ring-blue-100"
              />
              <button
                type="button"
                onClick={() => setShowPwd((v) => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showPwd ? (
                  <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
                  </svg>
                ) : (
                  <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                  </svg>
                )}
              </button>
            </div>
            <div className="flex items-center justify-end gap-2 pt-1">
              <button
                onClick={() => { setSetPwdUserId(null); setSetPwdUser(null); setNewPwd('') }}
                className="rounded-lg px-4 py-2 text-sm text-gray-600 hover:text-gray-900"
              >
                Cancelar
              </button>
              <button
                onClick={async () => {
                  if ((newPwd || '').length < 8) { toastError('La contraseña debe tener al menos 8 caracteres'); return }
                  try {
                    await setPasswordDirect(setPwdUserId!, newPwd)
                    success('Contraseña actualizada')
                    setSetPwdUserId(null)
                    setSetPwdUser(null)
                    setNewPwd('')
                  } catch (e: any) {
                    toastError(getErrorMessage(e))
                  }
                }}
                className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700"
              >
                Guardar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import React from 'react'

import { useNavigate, Link } from 'react-router-dom'

import { useAuth } from '../auth/AuthContext'

export interface LayoutProps {
  title?: string
  children: React.ReactNode
  empresaNombre?: string
  logoUrl?: string
  colorPrimario?: string
  showBackButton?: boolean
}

export const LayoutAdmin: React.FC<LayoutProps> = ({
  title = 'GestiqCloud',
  children,
  empresaNombre,
  logoUrl,
  showBackButton = true,
}) => {
  const navigate = useNavigate()
  const { profile, logout, brand } = useAuth()
  const isAdmin = !!profile?.is_superadmin

  React.useEffect(() => {
    if (title) document.title = title
  }, [title])

  const handleBack = () => {
    if (window.history.length > 1) navigate(-1)
    else navigate('/')
  }

  const handleLogout = async () => {
    try { await logout() } finally { navigate('/login', { replace: true }) }
  }

  const empresa = empresaNombre || brand || 'GestiqCloud'

  return (
    <div className="admin-shell-root">
      <header className="admin-topbar">
        <div className="admin-topbar__inner">
          <div className="admin-topbar__brand">
            {logoUrl ? (
              <img
                src={logoUrl}
                alt={empresa}
                className="admin-topbar__logo admin-topbar__logo--img"
              />
            ) : (
              <div className="admin-topbar__logo">GC</div>
            )}
            <div className="admin-topbar__brand-text">
              <span className="admin-topbar__brand-name">{empresa}</span>
              <span className="admin-topbar__brand-sub">Admin Panel</span>
            </div>
          </div>

          <nav className="admin-topbar__nav">
            {isAdmin && (
              <Link to="/admin" className="admin-topbar__btn">
                Panel Admin
              </Link>
            )}
            <button onClick={handleLogout} className="admin-topbar__btn admin-topbar__btn--logout">
              Cerrar sesión
            </button>
          </nav>
        </div>
      </header>

      <main className="admin-main-content">
        {showBackButton && (
          <button onClick={handleBack} className="admin-back-btn">
            ← Volver
          </button>
        )}
        {children}
      </main>

      <footer className="admin-footer">
        © {new Date().getFullYear()} GestiqCloud. Todos los derechos reservados.
      </footer>
    </div>
  )
}
